UPDATE wp_posts SET
  post_title = 'About DigiWin — 44 Years of Manufacturing Intelligence',
  post_content = '<!-- wp:divi/placeholder -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="about-hero">\n    <div class="hero-deco" aria-hidden="true"></div>\n            <div class="about-hero-inner">\n                <div class="about-hero-content">\n                    <h1><span class="dw-years">44</span> Years of Manufacturing Intelligence</h1>\n                    <p>From a Taiwanese startup in 1982 to the trusted ERP partner for 50,000+ manufacturers across Asia. We have survived every economic cycle—from the Asian Financial Crisis to Covid-19—without abandoning our manufacturing focus.</p>\n                    <a href="#mission" class="hero-scroll-cta">\n                        Explore Our Story\n                        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><path d="M12 5v14M5 12l7 7 7-7"/></svg>\n                    </a>\n                </div>\n                <div class="about-hero-stats">\n                    <div class="hero-stat">\n                        <div class="hero-stat-value">1982</div>\n                        <div class="hero-stat-label">Founded in Taiwan</div>\n                    </div>\n                    <div class="hero-stat">\n                        <div class="hero-stat-value">50K+</div>\n                        <div class="hero-stat-label">Manufacturing Clients</div>\n                    </div>\n                    <div class="hero-stat">\n                        <div class="hero-stat-value">1,600+</div>\n                        <div class="hero-stat-label">R&D Engineers</div>\n                    </div>\n                    <div class="hero-stat">\n                        <div class="hero-stat-value">300378</div>\n                        <div class="hero-stat-label">Shenzhen Stock Exchange</div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Mission"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Mission: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Mission: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="mission-section">\n    <div class="dw-d-bg dw-d-bg--center" style="opacity: 0.06;"></div>\n            <div class="mission-inner" style="position: relative; z-index: 2;">\n                <div class="mission-content">\n                    <h2>We Power Manufacturing\'s <span>Digital Future</span></h2>\n                    <p>DigiWin exists to help manufacturers see clearly, act decisively, and grow confidently. For over four decades, we\'ve been singularly focused on one thing: making factory operations visible, predictable, and profitable.</p>\n                    <p>We don\'t serve banks, retailers, or hospitals. We serve the shop floor—the engineers tracking BOMs, the planners scheduling production runs, the operators monitoring OEE in real time. This focus isn\'t a marketing position. It\'s our DNA.</p>\n                    <p>Every line of code we write, every consultant we train, every implementation we deliver is designed for one outcome: helping manufacturers compete and win.</p>\n                    <p>Today, we\'re transforming from a software vendor into an AI infrastructure provider. Backed by 1,600+ R&D engineers and 1,800+ implementation consultants, DigiWin has developed 168 AI Agents and 68 operational SOPs to standardize and accelerate digital transformation. DigiWin is pioneering the Zhuge Platform — where AI doesn\'t just report on your factory, it helps run it.</p>\n                    <div class="mission-origin">\n                        <div class="mission-origin-chinese">鼎新</div>\n                        <div class="mission-origin-pinyin">Dǐng Xīn</div>\n                        <div class="mission-origin-meaning">"To innovate, to renew" — This is the meaning behind our name. Founded by Sun Ai-bin and Gu Feng-yong in 1982, this philosophy has driven us for over four decades.</div>\n                    </div>\n                </div>\n                <div class="mission-visual">\n                    <div class="mission-image">\n                        <img src="/wp-content/uploads/2026/02/about-mission.jpg" alt="Smart factory floor with digital manufacturing technology" loading="lazy">\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Timeline"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Timeline: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Timeline: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="timeline-section">\n    <div class="timeline-inner">\n                <div class="timeline-header">\n                    <span class="section-label">STABILITY THROUGH DECADES</span>\n                    <h2><span class="dw-years">44</span> Years of Manufacturing Focus</h2>\n                    <p>Every crisis survived. Every technology wave embraced. One focus: manufacturing.</p>\n                </div>\n    \n                <div class="timeline-scroll-container">\n                    <div class="timeline-rail-wrapper">\n                        <div class="timeline-rail">\n                            \n                            <div class="milestone above">\n                                <div class="milestone-card">\n                                    <div class="milestone-year">1982</div>\n                                    <div class="milestone-title">Founded</div>\n                                    <div class="milestone-desc">DigiWin founded in Taiwan by Sun Ai-bin & Gu Feng-yong</div>\n                                    <span class="milestone-badge gold">Origin</span>\n                                </div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-dot glow"></div>\n                            </div>\n                            \n                            <div class="milestone below">\n                                <div class="milestone-dot"></div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-card">\n                                    <div class="milestone-year">1989</div>\n                                    <div class="milestone-title">First Product</div>\n                                    <div class="milestone-desc">First MRPII manufacturing software released</div>\n                                </div>\n                            </div>\n                            \n                            <div class="milestone above">\n                                <div class="milestone-card">\n                                    <div class="milestone-year">1992</div>\n                                    <div class="milestone-title">First Award</div>\n                                    <div class="milestone-desc">Taiwan Information Month Outstanding Software Package</div>\n                                </div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-dot"></div>\n                            </div>\n                            \n                            <div class="milestone below">\n                                <div class="milestone-dot"></div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-card">\n                                    <div class="milestone-year">1995</div>\n                                    <div class="milestone-title">TIPTOP ERP</div>\n                                    <div class="milestone-desc">Asia\'s first Browser/Server architecture ERP</div>\n                                </div>\n                            </div>\n                            \n                            <div class="milestone above">\n                                <div class="milestone-card">\n                                    <div class="milestone-year">2001</div>\n                                    <div class="milestone-title">Taiwan IPO</div>\n                                    <div class="milestone-desc">Listed on Taiwan Stock Exchange</div>\n                                    <span class="milestone-badge blue">TSEC</span>\n                                </div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-dot"></div>\n                            </div>\n                            \n                            <div class="milestone below">\n                                <div class="milestone-dot"></div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-card">\n                                    <div class="milestone-year">2006</div>\n                                    <div class="milestone-title">China #1</div>\n                                    <div class="milestone-desc">#1 Manufacturing ERP vendor in China</div>\n                                </div>\n                            </div>\n                            \n                            <div class="milestone above">\n                                <div class="milestone-card">\n                                    <div class="milestone-year">2014</div>\n                                    <div class="milestone-title">Shenzhen IPO</div>\n                                    <div class="milestone-desc">Listed on Shenzhen Stock Exchange (300378.SZ)</div>\n                                    <span class="milestone-badge blue">300378</span>\n                                </div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-dot glow"></div>\n                            </div>\n                            \n                            <div class="milestone below">\n                                <div class="milestone-dot"></div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-card">\n                                    <div class="milestone-year">2017</div>\n                                    <div class="milestone-title">Thailand</div>\n                                    <div class="milestone-desc">ASEAN expansion accelerates from Bangkok</div>\n                                    <span class="milestone-badge gold">ASEAN</span>\n                                </div>\n                            </div>\n                            \n                            <div class="milestone above">\n                                <div class="milestone-card">\n                                    <div class="milestone-year">2020</div>\n                                    <div class="milestone-title">Foxconn Invests</div>\n                                    <div class="milestone-desc">CNY 560M strategic investment from Foxconn FII</div>\n                                </div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-dot"></div>\n                            </div>\n                            \n                            <div class="milestone below">\n                                <div class="milestone-dot"></div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-card">\n                                    <div class="milestone-year">2022</div>\n                                    <div class="milestone-title">Red Dot Award</div>\n                                    <div class="milestone-desc">German Red Dot Design Award for Athena Platform</div>\n                                </div>\n                            </div>\n                            \n                            <div class="milestone above">\n                                <div class="milestone-card">\n                                    <div class="milestone-year">2024</div>\n                                    <div class="milestone-title">#1 PLM + MES</div>\n                                    <div class="milestone-desc">IDC #1 in discrete manufacturing, Indonesia entry</div>\n                                </div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-dot"></div>\n                            </div>\n                            \n                            <div class="milestone below">\n                                <div class="milestone-dot glow"></div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-card">\n                                    <div class="milestone-year">2026</div>\n                                    <div class="milestone-title">AI Era</div>\n                                    <div class="milestone-desc">SUPA AI framework, smart manufacturing intelligence</div>\n                                    <span class="milestone-badge green">Now</span>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                    <div class="scroll-hint">SCROLL →</div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Stats Banner"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Stats Banner: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Stats Banner: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="stats-banner" data-particles="bold">\n    <div class="stats-banner-inner" style="position: relative; z-index: 2;">\n                <div class="stat-item">\n                    <div class="stat-number"><span class="dw-years">44</span>+</div>\n                    <div class="stat-description">Years in Manufacturing ERP</div>\n                </div>\n                <div class="stat-item">\n                    <div class="stat-number">50K+</div>\n                    <div class="stat-description">Manufacturing Clients Worldwide</div>\n                </div>\n                <div class="stat-item">\n                    <div class="stat-number">100+</div>\n                    <div class="stat-description">Thai Implementations</div>\n                </div>\n                <div class="stat-item">\n                    <div class="stat-number">50+</div>\n                    <div class="stat-description">Team Members in Thailand</div>\n                </div>\n                <div class="stat-item">\n                    <div class="stat-number white">300378</div>\n                    <div class="stat-description">Shenzhen Stock Exchange Listed</div>\n                </div>\n            </div>\n    \n<script>\n(function(){\n  \'use strict\';\n  var reducedMotion=window.matchMedia(\'(prefers-reduced-motion: reduce)\').matches;\n  var PI2=Math.PI*2;\n  var BLUE=[0,175,240],CYAN=[0,230,255];\n  var PRESETS={\n    subtle:{frontOpacity:0.30,backOpacity:0.04,frontRadius:4.5,backRadius:0.6,color:BLUE,colorAlt:CYAN,altRatio:0.12},\n    medium:{frontOpacity:0.45,backOpacity:0.06,frontRadius:5.0,backRadius:0.8,color:BLUE,colorAlt:CYAN,altRatio:0.18},\n    bold:{frontOpacity:0.60,backOpacity:0.10,frontRadius:5.5,backRadius:1.0,color:CYAN,colorAlt:BLUE,altRatio:0.25}\n  };\n  function lerp(a,b,t){return a+(b-a)*t}\n  function DataOcean(el){\n    this.el=el;this.canvas=null;this.ctx=null;this.w=0;this.h=0;\n    this.dpr=Math.min(window.devicePixelRatio||1,2);this.visible=false;this.raf=null;this.time=0;this.resizeTimer=null;this.colors=null;\n    this.opts=this._parseOpts();this._setup();this._buildColors();this._observe();\n    if(!reducedMotion){this._loop()}else{this.visible=true;this._draw(0)}\n  }\n  DataOcean.prototype._parseOpts=function(){var n=this.el.getAttribute(\'data-particles\')||\'subtle\';if(n===\'\'||n===\'true\')n=\'subtle\';return PRESETS[n]||PRESETS.subtle};\n  DataOcean.prototype._setup=function(){\n    var c=document.createElement(\'canvas\');c.setAttribute(\'aria-hidden\',\'true\');\n    c.style.cssText=\'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;\';\n    var pos=getComputedStyle(this.el).position;if(pos===\'static\')this.el.style.position=\'relative\';\n    this.el.style.overflow=\'hidden\';this.el.insertBefore(c,this.el.firstChild);this.canvas=c;this.ctx=c.getContext(\'2d\');this._resize();\n    var self=this;window.addEventListener(\'resize\',function(){clearTimeout(self.resizeTimer);self.resizeTimer=setTimeout(function(){self._resize();self._buildColors()},200)});\n  };\n  DataOcean.prototype._resize=function(){var r=this.el.getBoundingClientRect();this.w=r.width;this.h=r.height;this.canvas.width=this.w*this.dpr;this.canvas.height=this.h*this.dpr;this.ctx.setTransform(this.dpr,0,0,this.dpr,0,0)};\n  DataOcean.prototype._buildColors=function(){var cols=Math.min(65,Math.ceil(this.w/22)+4);var rows=35;this._cols=cols;this._rows=rows;var n=cols*rows;this.colors=new Array(n);var alt=this.opts.altRatio;for(var i=0;i<n;i++){this.colors[i]=Math.random()<alt?this.opts.colorAlt:this.opts.color}};\n  DataOcean.prototype._observe=function(){var self=this;if(\'IntersectionObserver\' in window){this._obs=new IntersectionObserver(function(e){self.visible=e[0].isIntersecting},{rootMargin:\'150px 0px\'});this._obs.observe(this.el)}else{this.visible=true}};\n  DataOcean.prototype._loop=function(){var self=this;var last=0;(function tick(ts){self.raf=requestAnimationFrame(tick);if(!self.visible)return;if(ts-last<30)return;last=ts;self.time+=0.006;self._draw(self.time)})(0)};\n  DataOcean.prototype._draw=function(t){\n    var ctx=this.ctx,w=this.w,h=this.h,opts=this.opts,cols=this._cols,rows=this._rows;\n    ctx.clearRect(0,0,w,h);var ground=h+10,horizon=h*0.35,totalSpan=ground-horizon,idx=0;\n    for(var row=rows-1;row>=0;row--){\n      var depth=row/(rows-1),mappedDepth=Math.pow(depth,0.55),baseY=ground-mappedDepth*totalSpan;\n      var dotR=lerp(opts.frontRadius,opts.backRadius,depth),dotA=lerp(opts.frontOpacity,opts.backOpacity,depth);\n      var colSpacing=lerp(w/(cols-4),w/(cols+15),depth),rowShift=depth*w*0.12;\n      var waveScale=1-depth*0.75,amp1=70*waveScale,amp2=25*waveScale;\n      for(var col=0;col<cols;col++){\n        var screenX=col*colSpacing-rowShift+colSpacing*0.5;\n        if(screenX<-30||screenX>w+30){idx++;continue}\n        var worldX=col*24,worldZ=row*18;\n        var wave=amp1*Math.sin(worldX*0.0065+worldZ*0.012+t*0.9);\n        wave+=amp2*Math.sin(worldX*0.013-worldZ*0.008+t*0.55+1.8);\n        var screenY=baseY-wave;if(screenY<-15||screenY>h+15){idx++;continue}\n        var c=this.colors[idx%this.colors.length];\n        ctx.beginPath();ctx.arc(screenX,screenY,dotR,0,PI2);\n        ctx.fillStyle=\'rgba(\'+c[0]+\',\'+c[1]+\',\'+c[2]+\',\'+dotA+\')\';ctx.fill();idx++;\n      }\n    }\n  };\n  DataOcean.prototype.destroy=function(){if(this.raf)cancelAnimationFrame(this.raf);if(this._obs)this._obs.disconnect();if(this.canvas&&this.canvas.parentNode)this.canvas.parentNode.removeChild(this.canvas)};\n  function init(){var els=document.querySelectorAll(\'[data-particles]\');for(var i=0;i<els.length;i++)new DataOcean(els[i])}\n  if(document.readyState===\'loading\')document.addEventListener(\'DOMContentLoaded\',init);else init();\n})();\n</script>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Market Leadership"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Market Leadership: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Market Leadership: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="market-leadership">\n    <div class="market-leadership-inner scroll-fade-in">\n                <div class="market-leadership-header">\n                    <span class="section-label">RECOGNIZED BY INDUSTRY LEADERS</span>\n                    <h2>In Taiwan\'s Manufacturing Sector</h2>\n                </div>\n                <div class="market-leadership-grid">\n                    <div class="market-stat-card scroll-fade-in">\n                        <div class="market-stat-value">80%</div>\n                        <div class="market-stat-label">of Taiwan\'s Top 2,000 manufacturers use DigiWin solutions</div>\n                    </div>\n                    <div class="market-stat-card scroll-fade-in">\n                        <div class="market-stat-value">54%</div>\n                        <div class="market-stat-label">solutions market share in Taiwan\'s manufacturing ERP sector</div>\n                    </div>\n                    <div class="market-stat-card scroll-fade-in">\n                        <div class="market-stat-value">77%</div>\n                        <div class="market-stat-label">of Taiwan Stock Exchange IPO companies are DigiWin clients</div>\n                    </div>\n                </div>\n                <p class="market-leadership-source">Source: Common Wealth Magazine, 2023 Manufacturing Technology Survey</p>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Beliefs"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Beliefs: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Beliefs: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="beliefs-section">\n    <div class="dw-section-scene">\n                <svg aria-hidden="true" viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice">\n                    <path d="M250 200 L250 420 Q250 520 350 570 Q450 520 450 420 L450 200 L350 160Z" stroke="#000864" stroke-width="2" fill="none" opacity="0.1"/>\n                    <path d="M320 330 L345 355 L400 300" stroke="#00AFF0" stroke-width="2.5" fill="none" opacity="0.15"/>\n                    <circle cx="800" cy="200" r="60" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.08"/>\n                    <ellipse cx="800" cy="200" rx="30" ry="60" stroke="#000864" stroke-width="1" fill="none" opacity="0.06"/>\n                    <line x1="740" y1="200" x2="860" y2="200" stroke="#000864" stroke-width="1" opacity="0.06"/>\n                    <circle cx="780" cy="185" r="3" fill="#00AFF0" opacity="0.15"/>\n                    <circle cx="820" cy="210" r="3" fill="#00AFF0" opacity="0.12"/>\n                    <circle cx="795" cy="225" r="2.5" fill="#00AFF0" opacity="0.1"/>\n                    <line x1="100" y1="700" x2="600" y2="700" stroke="#000864" stroke-width="1" opacity="0.08"/>\n                    <line x1="100" y1="690" x2="100" y2="710" stroke="#000864" stroke-width="1" opacity="0.08"/>\n                    <line x1="350" y1="690" x2="350" y2="710" stroke="#000864" stroke-width="1" opacity="0.08"/>\n                    <line x1="600" y1="690" x2="600" y2="710" stroke="#000864" stroke-width="1" opacity="0.08"/>\n                    <text x="100" y="730" font-family="\'Noto Sans\',sans-serif" font-size="10" fill="#000864" opacity="0.06" text-anchor="middle">1982</text>\n                    <text x="350" y="730" font-family="\'Noto Sans\',sans-serif" font-size="10" fill="#000864" opacity="0.06" text-anchor="middle">2006</text>\n                    <text x="600" y="730" font-family="\'Noto Sans\',sans-serif" font-size="10" fill="#000864" opacity="0.06" text-anchor="middle">2026</text>\n                    <rect x="1050" y="400" width="200" height="120" rx="8" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.08"/>\n                    <line x1="1070" y1="440" x2="1230" y2="440" stroke="#000864" stroke-width="0.5" opacity="0.06"/>\n                    <line x1="1070" y1="460" x2="1200" y2="460" stroke="#000864" stroke-width="0.5" opacity="0.06"/>\n                    <line x1="1070" y1="480" x2="1210" y2="480" stroke="#000864" stroke-width="0.5" opacity="0.06"/>\n                    <text x="1150" y="420" font-family="\'Noto Sans\',sans-serif" font-size="9" font-weight="700" fill="#000864" opacity="0.06" text-anchor="middle">VALUES</text>\n                    <circle cx="650" cy="450" r="3" fill="#000864" opacity="0.06"/>\n                    <circle cx="1300" cy="300" r="4" fill="#000864" opacity="0.05"/>\n                    <circle cx="150" cy="500" r="3" fill="#00AFF0" opacity="0.08"/>\n                </svg>\n            </div>\n            <div class="beliefs-inner">\n                <div class="beliefs-header">\n                    <span class="section-label">OUR PHILOSOPHY</span>\n                    <h2>What We Believe</h2>\n                </div>\n                <div class="beliefs-grid">\n                    <div class="belief-card">\n                        <div class="belief-number">BELIEF 01</div>\n                        <h3>"Manufacturing Is Not Generic"</h3>\n                        <p>We don\'t sell to banks, retailers, or hospitals. We are manufacturing-only because the factory floor demands it. BOMs, routings, work orders, OEE—these aren\'t features we added; they\'re why we exist.</p>\n                    </div>\n                    <div class="belief-card">\n                        <div class="belief-number">BELIEF 02</div>\n                        <h3>"Grow Together, Not Apart"</h3>\n                        <p>Our product suite—iGP → T100 → MES → WMS → AIoT—means your ERP partner doesn\'t change as your business scales. Your investment compounds, never resets. From 20-person workshop to multi-site enterprise group.</p>\n                    </div>\n                    <div class="belief-card">\n                        <div class="belief-number">BELIEF 03</div>\n                        <h3>"Local Roots, Global Standards"</h3>\n                        <p>Our Thailand team speaks Thai, understands Thai business culture, and is backed by 44 years of global manufacturing expertise. We\'re not a remote vendor sending consultants from overseas—we\'re here.</p>\n                    </div>\n                    <div class="belief-card">\n                        <div class="belief-number">BELIEF 04</div>\n                        <h3>"Data Should Liberate, Not Complicate"</h3>\n                        <p>We turn factory chaos—shadow Excel, ghost inventory, disconnected systems—into clear, actionable intelligence. Your production manager shouldn\'t need 3 spreadsheets to answer a simple question.</p>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="outcomes-section">\n    <div class="outcomes-inner">\n                <div class="outcomes-visual">\n                    <div class="outcomes-image">\n                        <img src="/wp-content/uploads/2026/02/about-outcomes.jpg" alt="Team collaborating in modern manufacturing workspace" loading="lazy">\n                    </div>\n                </div>\n                <div class="outcomes-content">\n                    <h2>Because of DigiWin, <span>You Can...</span></h2>\n    \n                    <div class="outcome-item">\n                        <div class="outcome-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><circle cx="12" cy="12" r="10"/><path d="M12 6v6l4 2"/></svg>\n                        </div>\n                        <div class="outcome-text">\n                            <h3>See Your Factory in Real Time</h3>\n                            <p>MES and AIoT give you live production data, not yesterday\'s spreadsheet. Know what\'s happening now, not what happened last shift.</p>\n                        </div>\n                    </div>\n    \n                    <div class="outcome-item">\n                        <div class="outcome-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><path d="M12 2v20M17 5H9.5a3.5 3.5 0 000 7h5a3.5 3.5 0 010 7H6"/></svg>\n                        </div>\n                        <div class="outcome-text">\n                            <h3>Control Costs Before They Control You</h3>\n                            <p>Material tracking, scrap reduction, yield optimization across every production run. See waste before it becomes loss.</p>\n                        </div>\n                    </div>\n    \n                    <div class="outcome-item">\n                        <div class="outcome-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><path d="M5 12h14M12 5l7 7-7 7"/></svg>\n                        </div>\n                        <div class="outcome-text">\n                            <h3>Ship On Time, Every Time</h3>\n                            <p>Production scheduling and WMS working together to meet customer delivery promises. No more expediting chaos.</p>\n                        </div>\n                    </div>\n    \n                    <div class="outcome-item">\n                        <div class="outcome-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><path d="M21 16V8a2 2 0 00-1-1.73l-7-4a2 2 0 00-2 0l-7 4A2 2 0 003 8v8a2 2 0 001 1.73l7 4a2 2 0 002 0l7-4A2 2 0 0021 16z"/></svg>\n                        </div>\n                        <div class="outcome-text">\n                            <h3>Scale Without Starting Over</h3>\n                            <p>One ecosystem from workshop to enterprise group. Add MES when you\'re ready, add WMS when you need it. Your foundation stays solid.</p>\n                        </div>\n                    </div>\n    \n                    <div class="outcome-item">\n                        <div class="outcome-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><path d="M22 11.08V12a10 10 0 11-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>\n                        </div>\n                        <div class="outcome-text">\n                            <h3>Pass BOI Audits with Confidence</h3>\n                            <p>Production-order-level material reconciliation that matches exactly what the BOI board audits. One client saved 10M+ THB/year in supplementary taxes. Thai Revenue Department certified, with full traceability and audit trails built into every process.</p>\n                        </div>\n                    </div>\n    \n                    <div class="outcome-item">\n                        <div class="outcome-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><path d="M2 3h6a4 4 0 014 4v14a3 3 0 00-3-3H2zM22 3h-6a4 4 0 00-4 4v14a3 3 0 013-3h7z"/></svg>\n                        </div>\n                        <div class="outcome-text">\n                            <h3>Make Decisions with Confidence</h3>\n                            <p>BI dashboards and analytics that turn raw data into strategic clarity. See the patterns, not just the numbers.</p>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Thailand"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Thailand: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Thailand: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="thailand-section">\n    <div class="thailand-inner" style="position: relative; z-index: 2;">\n                <div class="thailand-header">\n                    <span class="section-label">PROVEN IN YOUR NEIGHBORHOOD</span>\n                    <h2>Thailand Commitment</h2>\n                    <p>Real support, no translation needed. You are not the "guinea pig."</p>\n                </div>\n                <div class="thailand-content">\n                    <div class="thailand-text">\n                        <div class="thailand-proof-grid">\n                            <div class="thailand-proof">\n                                <span class="proof-number">100+</span>\n                                <span class="proof-text">Customers & Partners in Thailand</span>\n                            </div>\n                            <div class="thailand-proof">\n                                <span class="proof-number">50+</span>\n                                <span class="proof-text">Thai Team Members</span>\n                            </div>\n                            <div class="thailand-proof">\n                                <span class="proof-number">60%+</span>\n                                <span class="proof-text">Bilingual (Thai + Chinese)</span>\n                            </div>\n                            <div class="thailand-proof">\n                                <span class="proof-number">Since 2017</span>\n                                <span class="proof-text">Serving Thai Manufacturers</span>\n                            </div>\n                        </div>\n    \n                        <p style="font-size: 15px; color: #475569; line-height: 1.8; margin: 24px 0;">DigiWin entered Thailand in 2017, initially serving Taiwanese and Chinese manufacturers who had set up operations here. As demand grew, we formally registered our Thai company in 2019 and built a local team from the ground up—hiring Thai consultants, learning Thai business culture, and building relationships with Thai factory owners. Today, we serve the Thai local market directly with 50+ team members. We\'re not a remote vendor sending consultants from overseas. We\'re your neighbor.</p>\n    \n                        <h3>Named Thai References</h3>\n                        <p class="reference-intro">Active production environments running on our systems today:</p>\n                        <div class="reference-logos">\n                            <span class="reference-name">GoldenSea Sanki</span>\n                            <span class="reference-name">Top Mould</span>\n                            <span class="reference-name">Accauto</span>\n                            <span class="reference-name">Unique New Energy</span>\n                            <span class="reference-name">Intensive Mould</span>\n                        </div>\n    \n                        <h3>Thai Compliance Ready</h3>\n                        <ul class="thailand-highlights">\n                            <li>\n                                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="20 6 9 17 4 12"/></svg>\n                                <span><strong>Thai Revenue Department certified</strong></span>\n                            </li>\n                            <li>\n                                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="20 6 9 17 4 12"/></svg>\n                                <span>Withholding Tax logic built-in</span>\n                            </li>\n                            <li>\n                                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="20 6 9 17 4 12"/></svg>\n                                <span>e-Tax integration ready</span>\n                            </li>\n                            <li>\n                                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="20 6 9 17 4 12"/></svg>\n                                <span>BOI reporting support</span>\n                            </li>\n                        </ul>\n                    </div>\n                    <div class="contact-card">\n                        <h3>Thailand Office</h3>\n                        <div class="contact-item">\n                            <div class="contact-label">Address</div>\n                            <div class="contact-value">No. 2/117-118, Bangna Complex Office Tower,<br>22nd Floor, Theparat Road,<br>Bangna, Bangkok 10260</div>\n                        </div>\n                        <div class="contact-item">\n                            <div class="contact-label">Email</div>\n                            <div class="contact-value"><a href="mailto:info@digiwin.co.th">info@digiwin.co.th</a></div>\n                        </div>\n                        <a href="/contact/" class="contact-cta">Get in Touch →</a>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Asia Presence"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Asia Presence: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Asia Presence: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="asia-presence">\n    <div class="asia-presence-inner">\n                <div class="asia-header">\n                    <span class="section-label">ACROSS ASIA-PACIFIC</span>\n                    <h2>Regional Presence</h2>\n                    <p>Dual headquarters in Taiwan and Shanghai, with 43 offices across China and ASEAN.</p>\n                </div>\n    \n                \n                <div class="asia-map-visual">\n                    <svg aria-hidden="true" class="asia-map-svg" viewBox="0 0 1000 800" fill="none" preserveAspectRatio="xMidYMid meet">\n                        <defs>\n                            <filter id="glow">\n                                <feGaussianBlur stdDeviation="2" result="coloredBlur"/>\n                                <feMerge><feMergeNode in="coloredBlur"/><feMergeNode in="SourceGraphic"/></f