40" x2="400" y2="660" stroke="#000864" stroke-width="1.5" opacity="0.08"/>\n                    <line x1="700" y1="640" x2="700" y2="660" stroke="#000864" stroke-width="1.5" opacity="0.08"/>\n                    <line x1="1000" y1="640" x2="1000" y2="660" stroke="#000864" stroke-width="1.5" opacity="0.08"/>\n                    <line x1="1300" y1="640" x2="1300" y2="660" stroke="#000864" stroke-width="1.5" opacity="0.08"/>\n                    <text x="100" y="680" font-family="\'Noto Sans\',sans-serif" font-size="10" fill="#000864" opacity="0.06" text-anchor="middle">1996</text>\n                    <text x="700" y="680" font-family="\'Noto Sans\',sans-serif" font-size="10" fill="#000864" opacity="0.06" text-anchor="middle">2010</text>\n                    <text x="1300" y="680" font-family="\'Noto Sans\',sans-serif" font-size="10" fill="#000864" opacity="0.06" text-anchor="middle">2025</text>\n                    <path d="M500 500 L500 480 L520 480" stroke="#000864" stroke-width="1" fill="none" opacity="0.08"/>\n                    <path d="M900 550 L920 550 L920 530" stroke="#000864" stroke-width="1" fill="none" opacity="0.08"/>\n                    <circle cx="600" cy="400" r="3" fill="#000864" opacity="0.06"/>\n                    <circle cx="1050" cy="550" r="4" fill="#00AFF0" opacity="0.06"/>\n                    <circle cx="200" cy="550" r="3" fill="#000864" opacity="0.05"/>\n                </svg>\n            </div>\n            <div class="awards-inner">\n                <div class="awards-header">\n                    <span class="section-label">THIRD-PARTY VALIDATION</span>\n                    <h2>Awards & Recognition</h2>\n                    <p>Industry analysts and certification bodies validate what our customers already know.</p>\n                </div>\n    \n                <div class="awards-grid">\n                    <div class="award-card">\n                        <div class="award-icon gold">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><circle cx="12" cy="8" r="6"/><path d="M15.477 12.89L17 22l-5-3-5 3 1.523-9.11"/></svg>\n                        </div>\n                        <div class="award-year">2022</div>\n                        <h3>German Red Dot Design Award</h3>\n                        <p>Digiwin Athena Platform recognized for innovative industrial software design</p>\n                    </div>\n    \n                    <div class="award-card">\n                        <div class="award-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"/></svg>\n                        </div>\n                        <div class="award-year">2024-2025</div>\n                        <h3>#1 PLM + MES Market Share</h3>\n                        <p>IDC rankings: 32% market share in discrete manufacturing for 3 consecutive years</p>\n                    </div>\n    \n                    <div class="award-card">\n                        <div class="award-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><path d="M22 11.08V12a10 10 0 11-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>\n                        </div>\n                        <div class="award-year">2010</div>\n                        <h3>CMMI Level 4</h3>\n                        <p>Quantitatively managed software processes—rare credential for ERP vendors</p>\n                    </div>\n    \n                    <div class="award-card">\n                        <div class="award-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><rect x="3" y="11" width="18" height="11" rx="2"/><path d="M7 11V7a5 5 0 0110 0v4"/></svg>\n                        </div>\n                        <div class="award-year">1996–2025</div>\n                        <h3>ISO 9001 & 27001</h3>\n                        <p>Continuous quality and information security certification for 29 years</p>\n                    </div>\n    \n                    <div class="award-card">\n                        <div class="award-icon gold">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/></svg>\n                        </div>\n                        <div class="award-year">2013</div>\n                        <h3>National Industry Innovation Award</h3>\n                        <p>Taiwan Ministry of Economic Affairs recognition for industry contribution</p>\n                    </div>\n    \n                    <div class="award-card">\n                        <div class="award-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><path d="M21 16V8a2 2 0 00-1-1.73l-7-4a2 2 0 00-2 0l-7 4A2 2 0 003 8v8a2 2 0 001 1.73l7 4a2 2 0 002 0l7-4A2 2 0 0021 16z"/><polyline points="7.5 4.21 12 6.81 16.5 4.21"/><polyline points="7.5 19.79 7.5 14.6 3 12"/><polyline points="21 12 16.5 14.6 16.5 19.79"/><polyline points="3.27 6.96 12 12.01 20.73 6.96"/><line x1="12" y1="22.08" x2="12" y2="12"/></svg>\n                        </div>\n                        <div class="award-year">2024</div>\n                        <h3>Industrial Internet Excellent Solution</h3>\n                        <p>PLM category recognition for smart manufacturing innovation</p>\n                    </div>\n    \n                    <div class="award-card">\n                        <div class="award-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><circle cx="12" cy="12" r="10"/><path d="M8 14s1.5 2 4 2 4-2 4-2M9 9h.01M15 9h.01"/></svg>\n                        </div>\n                        <div class="award-year">1992</div>\n                        <h3>Taiwan\'s First ERP Software Award</h3>\n                        <p>Information Month Outstanding Software Package—our first industry recognition</p>\n                    </div>\n    \n                    <div class="award-card">\n                        <div class="award-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 00-3-3.87M16 3.13a4 4 0 010 7.75"/></svg>\n                        </div>\n                        <div class="award-year">2020</div>\n                        <h3>Foxconn Strategic Investment</h3>\n                        <p>CNY 560M from world\'s largest electronics manufacturer validates our technology</p>\n                    </div>\n                </div>\n    \n                <div class="certifications-bar">\n                    <div class="cert-item">\n                        <div class="cert-badge">ISO 27001</div>\n                        <div class="cert-label">Information Security</div>\n                    </div>\n                    <div class="cert-item">\n                        <div class="cert-badge">ISO 9001</div>\n                        <div class="cert-label">Quality Management</div>\n                    </div>\n                    <div class="cert-item">\n                        <div class="cert-badge">CMMI L4</div>\n                        <div class="cert-label">Process Maturity</div>\n                    </div>\n                    <div class="cert-item">\n                        <div class="cert-badge">Thai RD</div>\n                        <div class="cert-label">Revenue Dept. Certified</div>\n                    </div>\n                    <div class="cert-item">\n                        <div class="cert-badge">300378.SZ</div>\n                        <div class="cert-label">Shenzhen Listed</div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="about-cta-section">\n    <div class="about-cta-super-d" aria-hidden="true"></div>\n    <div class="about-cta-wave-flow" aria-hidden="true"></div>\n    <div class="about-cta-container">\n      <h2 class="about-cta-title">Ready to Work with a Team That Understands Manufacturing?</h2>\n      <p class="about-cta-subtitle">See how <span class="dw-years">44</span> years of manufacturing expertise—backed by Foxconn FII—can help you compete on the global stage.</p>\n      <div class="about-cta-btn-row">\n        <a href="/contact/" class="about-cta-btn about-cta-btn--primary">Let’s Talk</a>\n        <a href="/partner-program/" class="about-cta-btn about-cta-btn--ghost">Become a Partner</a>\n      </div>\n    <div class="about-cta-contact-info"><div class="about-cta-contact-item"><svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg><span>No. 2/117-118, Bangna Complex Office Tower, 22F, Theparat Rd, Bangna, Bangkok 10260</span></div><div class="about-cta-contact-item"><svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z"/><polyline points="22,6 12,13 2,6"/></svg><a href="mailto:info@digiwin.co.th">info@digiwin.co.th</a></div></div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100568;

-- Step 2: Update Divi 5 custom CSS
DELETE FROM wp_postmeta WHERE post_id = 100568 AND meta_key = '_et_pb_custom_css';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100568, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === HERO (S1) === */\n/* TODO: Review and remap class selectors to use hero prefix */\n/* TODO: Add section container: .hero-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n.about-hero {\n            background: linear-gradient(135deg, #000432 0%, #000864 50%, #001080 100%);\n            padding: 140px 24px 100px;\n            position: relative;\n            overflow: hidden;\n        }\n.about-hero::before {\n            content: \'\';\n            position: absolute;\n            inset: 0;\n            background-image: url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");\n            pointer-events: none;\n        }\n.about-hero-inner {\n            max-width: 1200px;\n            margin: 0 auto;\n            position: relative;\n            z-index: 1;\n            display: grid;\n            grid-template-columns: 1fr 1fr;\n            gap: 80px;\n            align-items: center;\n        }\n.about-hero-content h1 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: clamp(36px, 5vw, 52px);\n            font-weight: 700;\n            color: #fff;\n            line-height: 1.15;\n            margin-bottom: 24px;\n        }\n.about-hero-content h1 span {\n            color: #00AFF0;\n        }\n.about-hero-content p {\n            font-size: 18px;\n            color: rgba(255,255,255,0.85);\n            line-height: 1.7;\n            margin-bottom: 24px;\n        }\n.hero-scroll-cta {\n            display: inline-flex;\n            align-items: center;\n            gap: 8px;\n            color: #00AFF0;\n            font-weight: 600;\n            font-size: 15px;\n            text-decoration: none;\n            transition: all 0.3s ease;\n        }\n.hero-scroll-cta:hover {\n            gap: 12px;\n        }\n.hero-scroll-cta svg {\n            width: 20px;\n            height: 20px;\n            stroke: currentColor;\n            animation: bounce-down 2s ease-in-out infinite;\n        }\n@keyframes bounce-down {\n            0%, 100% { transform: translateY(0); }\n            50% { transform: translateY(6px); }\n        }\n.about-hero-stats {\n            display: grid;\n            grid-template-columns: repeat(2, 1fr);\n            gap: 24px;\n        }\n.hero-stat {\n            background: rgba(255,255,255,0.05);\n            border: 1px solid rgba(255,255,255,0.1);\n            border-radius: 16px;\n            padding: 32px;\n            text-align: center;\n        }\n.hero-stat-value {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 48px;\n            font-weight: 700;\n            color: #00AFF0;\n            line-height: 1;\n            margin-bottom: 8px;\n        }\n.hero-stat-label {\n            font-size: 14px;\n            color: rgba(255,255,255,0.75);\n        }\n@media (max-width: 1024px) {\n  .about-hero-inner{grid-template-columns:1fr;gap:48px}\n  .about-hero-stats{max-width:400px;margin:0 auto}\n}\n@media (max-width: 768px) {\n  .hero-scroll-cta{min-height:44px}\n}\n@media (max-width: 640px) {\n  .about-hero{padding:120px 20px 80px}\n  .about-hero-content h1{font-size:28px}\n  .about-hero-stats{grid-template-columns:1fr}\n}\n\n/* Divi overrides */\n.et_pb_section .about-hero-content h1{font-weight:700 !important;line-height:1.15 !important}\n.et_pb_section .about-hero-content p{padding-bottom:0 !important;line-height:30.6px !important}\n.et_pb_section .hero-stat-value{line-height:48px !important;color:#00AFF0 !important}\n.et_pb_section .hero-stat-label{line-height:22.4px !important}\n\n/* Defensive SVG sizing */\nsvg:not([width]):not([class]){max-width:48px;max-height:48px}\n@media(prefers-reduced-motion:reduce){}\n\n/* Super D decoration — unique class to avoid cascade conflict with other sections\' dw-d-bg */\n.hero-deco{position:absolute;top:50%;right:auto;left:-15%;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center left;background-size:contain;transform:translateY(-50%);opacity:0.16;pointer-events:none;z-index:0}\n/* === MISSION (S2) === */\n.mission-section {\n            padding: 100px 24px;\n            background: #fff;\n            -webkit-font-smoothing: auto;\n            -moz-osx-font-smoothing: auto;\n        }\n.mission-inner {\n            max-width: 1100px;\n            margin: 0 auto;\n            display: grid;\n            grid-template-columns: 1.2fr 1fr;\n            gap: 80px;\n            align-items: center;\n        }\n.mission-content h2 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 36px;\n            font-weight: 700;\n            color: #000864;\n            margin-bottom: 32px;\n            line-height: 1.2;\n        }\n.mission-content h2 span {\n            color: #0369a1;\n        }\n.mission-content p {\n            font-size: 17px;\n            color: #475569;\n            line-height: 1.8;\n            margin-bottom: 24px;\n        }\n.mission-origin {\n            background: linear-gradient(135deg, #eff6ff, #dbeafe);\n            border-left: 4px solid #00AFF0;\n            padding: 24px 28px;\n            border-radius: 0 12px 12px 0;\n            margin-top: 32px;\n        }\n.mission-origin-chinese {\n            font-family: \'Noto Sans TC\', sans-serif;\n            font-size: 32px;\n            font-weight: 700;\n            color: #000864;\n            margin-bottom: 8px;\n            line-height: 51.2px;\n        }\n.mission-origin-pinyin {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 14px;\n            color: #5b6b80;\n            margin-bottom: 12px;\n            line-height: 22.4px;\n        }\n.mission-origin-meaning {\n            font-size: 15px;\n            color: #475569;\n            font-style: italic;\n        }\n.mission-visual {\n            position: relative;\n        }\n.mission-image {\n            width: 100%;\n            height: 400px;\n            border-radius: 24px;\n            overflow: hidden;\n            position: relative;\n        }\n.mission-image img {\n            width: 100%;\n            height: 100%;\n            object-fit: cover;\n        }\n@media (max-width: 1024px) {\n  .mission-inner{grid-template-columns:1fr;gap:48px}\n}\n@media (max-width: 640px) {\n  .mission-image{height:280px}\n  .mission-content h2{font-size:28px}\n}\n\n/* Divi overrides */\n.et_pb_section .mission-content h2{font-weight:700 !important;line-height:1.2 !important}\n.et_pb_section .mission-content p{padding-bottom:0 !important;line-height:30.6px !important}\n.et_pb_section .mission-origin-meaning{line-height:24px !important;padding-bottom:0 !important}\n\n@media(prefers-reduced-motion:reduce){}\n\n/* Super D decoration */\n.dw-d-bg{position:absolute;top:50%;right:auto;left:50%;width:80%;min-height:80vh;background:url("data:image/svg+xml;base64,") no-repeat center center;background-size:contain;transform:translate(-50%, -50%);opacity:0.06;pointer-events:none;z-index:0}\n/* === TIMELINE (S3) === */\n/* TODO: Review and remap class selectors to use tim prefix */\n/* TODO: Add section container: .timeline-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n.timeline-section {\n            padding: 80px 24px;\n            background: linear-gradient(180deg, #000864 0%, #000432 100%);\n      