cene svg{position:absolute;top:0;left:0;width:100%;height:100%;pointer-events:none}\n\n/* Divi overrides */\n.et_pb_section .awards-header h2{font-weight:700 !important;line-height:1.2 !important}\n.et_pb_section .award-card h3{line-height:29.952px !important;font-weight:700 !important;font-size:18.72px !important;color:rgb(51,51,51) !important}\n.et_pb_section .award-card p{padding-bottom:0 !important}\n.awards-section .section-label{color:#0369a1}\n\n@media(prefers-reduced-motion:reduce){}\n\n/* Super D decoration */\n.dw-d-bg{position:absolute;top:50%;right:-10%;left:auto;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center right;background-size:contain;transform:translateY(-50%);opacity:0.12;pointer-events:none;z-index:0}\n/* === CTA === */\n.about-cta-section{background:linear-gradient(135deg, #00AFF0 0%, #003CC8 50%, #001080 100%);padding:100px 24px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.about-cta-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'20\' height=\'20\' viewBox=\'0 0 20 20\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cpath d=\'M10 0v20M0 10h20\' stroke=\'%23fff\' stroke-width=\'0.5\' opacity=\'0.05\'/%3E%3C/svg%3E");pointer-events:none;z-index:1}\n.about-cta-section::after{content:\'\';position:absolute;bottom:-20%;right:-10%;width:80%;height:80%;background:radial-gradient(ellipse at center,rgba(255,255,255,0.1) 0%,transparent 70%);pointer-events:none;z-index:1}\n.about-cta-super-d{position:absolute;top:50%;right:-10%;left:auto;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center right;background-size:contain;transform:translateY(-50%);opacity:0.12;pointer-events:none;z-index:0}\n.about-cta-wave-flow{position:absolute;bottom:0;left:0;right:0;height:160px;background:linear-gradient(180deg,transparent,rgba(0,60,200,0.15));opacity:0.3