\n  .about-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .about-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .about-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.about-cta-btn{transition:none !important}.about-cta-btn::before{display:none}}\n.about-cta-btn--primary{color:rgb(3,105,161) !important;box-shadow:rgba(0,0,0,0.15) 0px 4px 14px 0px !important}\n.about-cta-btn--ghost{padding:20px 40px !important;border-color:rgba(255,255,255,0.5) !important;border-radius:14px !important}\n.about-cta-subtitle{line-height:28.8px !important}\n.about-cta-subtitle .dw-years{line-height:28.8px !important}\n.about-cta-contact-info{display:flex;gap:40px;justify-content:center;flex-wrap:wrap;margin-top:40px;position:relative;z-index:3}\n.et_pb_section .about-cta-contact-item{display:flex;align-items:center;gap:10px;font-family:\'Noto Sans\',sans-serif;font-size:15px;color:rgba(255,255,255,0.85) !important}\n.et_pb_section .about-cta-contact-item svg{width:18px;height:18px;flex-shrink:0;stroke:rgba(255,255,255,0.85)}\n.et_pb_section .about-cta-contact-item span{color:rgba(255,255,255,0.85) !important;font-size:15px !important;font-family:\'Noto Sans\',sans-serif !important}\n.et_pb_section .about-cta-contact-item a{color:#fff !important;text-decoration:none !important;font-size:15px !important;font-family:\'Noto Sans\',sans-serif !important}\n.et_pb_section .about-cta-contact-item a:hover{text-decoration:underline !important}\n\n/* === TB BODY WRAPPER RESET (must be last — specificity 0,4,0 beats all :has() rules at 0,3,0) === */\n.et-l--body .et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et-l--body .et_pb_row[class*="tb_body"]{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et-l--body .et_pb_column[class*="tb_body"]{padding:0 !important