UPDATE wp_posts SET
  post_title = 'เกี่ยวกับ DigiWin — 44 ปีแห่งความเชี่ยวชาญด้านการผลิต',
  post_content = '<!-- wp:divi/placeholder -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"ฮีโร่: เกี่ยวกับเรา"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"ฮีโร่: เกี่ยวกับเรา: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"ฮีโร่: เกี่ยวกับเรา: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="about-hero">\n    <div class="hero-deco" aria-hidden="true"></div>\n            <div class="about-hero-inner">\n                <div class="about-hero-content">\n                    <h1><span class="dw-years">44</span> ปีแห่งความเชี่ยวชาญด้านการผลิตอัจฉริยะ</h1>\n                    <p>จากสตาร์ทอัพไต้หวันในปี 1982 สู่พันธมิตร ERP ที่ผู้ผลิตกว่า 50,000+ รายทั่วเอเชียไว้วางใจ เราผ่านทุกวิกฤตเศรษฐกิจ—ตั้งแต่วิกฤตต้มยำกุ้งจนถึง Covid-19—โดยไม่เคยละทิ้งความมุ่งมั่นในภาคการผลิต</p>\n                    <a href="#mission" class="hero-scroll-cta">\n                        สำรวจเรื่องราวของเรา\n                        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><path d="M12 5v14M5 12l7 7 7-7"/></svg>\n                    </a>\n                </div>\n                <div class="about-hero-stats">\n                    <div class="hero-stat">\n                        <div class="hero-stat-value">1982</div>\n                        <div class="hero-stat-label">ก่อตั้งที่ไต้หวัน</div>\n                    </div>\n                    <div class="hero-stat">\n                        <div class="hero-stat-value">50K+</div>\n                        <div class="hero-stat-label">ลูกค้าโรงงานผลิต</div>\n                    </div>\n                    <div class="hero-stat">\n                        <div class="hero-stat-value">1,600+</div>\n                        <div class="hero-stat-label">วิศวกร R&D</div>\n                    </div>\n                    <div class="hero-stat">\n                        <div class="hero-stat-value">300378</div>\n                        <div class="hero-stat-label">จดทะเบียนตลาดหลักทรัพย์เสิ่นเจิ้น</div>\n                    </div>\n                </div>\n            </div>\n    <script>(function(){var y=new Date().getFullYear();document.querySelectorAll(\'.dw-years\').forEach(function(e){e.textContent=y-1982})})();</script>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"พันธกิจ"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"พันธกิจ: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"พันธกิจ: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="mission-section">\n    <div class="dw-d-bg dw-d-bg--center" style="opacity: 0.06;"></div>\n            <div class="mission-inner" style="position: relative; z-index: 2;">\n                <div class="mission-content">\n                    <h2>เราขับเคลื่อน<span>อนาคตดิจิทัล</span>ของภาคการผลิต</h2>\n                    <p>DigiWin มีเป้าหมายเพื่อช่วยให้ผู้ผลิตมองเห็นข้อมูลอย่างชัดเจน ตัดสินใจอย่างมั่นใจ และเติบโตอย่างยั่งยืน กว่าสี่ทศวรรษ เรามุ่งมั่นในสิ่งเดียว: ทำให้การดำเนินงานโรงงานมองเห็นได้ คาดการณ์ได้ และทำกำไรได้</p>\n                    <p>เราไม่ได้ให้บริการธนาคาร ห้างค้าปลีก หรือโรงพยาบาล เราให้บริการพื้นที่หน้างาน—วิศวกรที่ติดตาม BOM (รายการวัสดุ) นักวางแผนที่จัดตาราง Production Run ผู้ปฏิบัติงานที่ติดตาม OEE (ประสิทธิผลโดยรวมของเครื่องจักร) แบบ Real-time จุดยืนนี้ไม่ใช่กลยุทธ์การตลาด แต่เป็น DNA ของเรา</p>\n                    <p>โค้ดทุกบรรทัดที่เราเขียน ที่ปรึกษาทุกคนที่เราฝึก การติดตั้งทุกครั้งที่เราส่งมอบ ล้วนออกแบบมาเพื่อผลลัพธ์เดียว: ช่วยให้ผู้ผลิตแข่งขันและชนะ</p>\n                    <p>วันนี้ เรากำลังเปลี่ยนจากผู้จำหน่ายซอฟต์แวร์สู่ผู้ให้บริการโครงสร้างพื้นฐาน AI โดยมีวิศวกร R&D กว่า 1,600+ คนและที่ปรึกษาการติดตั้งกว่า 1,800+ คน DigiWin ได้พัฒนา AI Agent 168 ตัวและ SOP ปฏิบัติการ 68 รายการ เพื่อมาตรฐานและเร่งกระบวนการ Digital Transformation</p>\n                    <div class="mission-origin">\n                        <div class="mission-origin-chinese">鼎新</div>\n                        <div class="mission-origin-pinyin">Dǐng Xīn</div>\n                        <div class="mission-origin-meaning">"สร้างสรรค์สิ่งใหม่ ฟื้นฟูให้ดีกว่าเดิม" — นี่คือความหมายเบื้องหลังชื่อของเรา ก่อตั้งโดย Sun Ai-bin และ Gu Feng-yong ในปี 1982 ปรัชญานี้ขับเคลื่อนเรามากว่าสี่ทศวรรษ</div>\n                    </div>\n                </div>\n                <div class="mission-visual">\n                    <div class="mission-image">\n                        <img src="/wp-content/uploads/2026/02/about-mission.jpg" alt="พื้นที่หน้างานอัจฉริยะพร้อมเทคโนโลยีการผลิตดิจิทัล" loading="lazy">\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"ไทม์ไลน์"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"ไทม์ไลน์: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"ไทม์ไลน์: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="timeline-section">\n    <div class="timeline-inner">\n                <div class="timeline-header">\n                    <span class="section-label">มั่นคงผ่านทุกยุคสมัย</span>\n                    <h2><span class="dw-years">44</span> ปีแห่งความมุ่งมั่นในภาคการผลิต</h2>\n                    <p>ผ่านทุกวิกฤต รับทุกคลื่นเทคโนโลยี จุดยืนเดียว: การผลิต</p>\n                </div>\n\n                <div class="timeline-scroll-container">\n                    <div class="timeline-rail-wrapper">\n                        <div class="timeline-rail">\n\n                            <div class="milestone above">\n                                <div class="milestone-card">\n                                    <div class="milestone-year">1982</div>\n                                    <div class="milestone-title">ก่อตั้งบริษัท</div>\n                                    <div class="milestone-desc">DigiWin ก่อตั้งที่ไต้หวันโดย Sun Ai-bin และ Gu Feng-yong</div>\n                                    <span class="milestone-badge gold">จุดเริ่มต้น</span>\n                                </div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-dot glow"></div>\n                            </div>\n\n                            <div class="milestone below">\n                                <div class="milestone-dot"></div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-card">\n                                    <div class="milestone-year">1989</div>\n                                    <div class="milestone-title">ผลิตภัณฑ์แรก</div>\n                                    <div class="milestone-desc">เปิดตัวซอฟต์แวร์การผลิต MRPII ตัวแรก</div>\n                                </div>\n                            </div>\n\n                            <div class="milestone above">\n                                <div class="milestone-card">\n                                    <div class="milestone-year">1992</div>\n                                    <div class="milestone-title">รางวัลแรก</div>\n                                    <div class="milestone-desc">รางวัลซอฟต์แวร์ดีเด่น Taiwan Information Month</div>\n                                </div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-dot"></div>\n                            </div>\n\n                            <div class="milestone below">\n                                <div class="milestone-dot"></div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-card">\n                                    <div class="milestone-year">1995</div>\n                                    <div class="milestone-title">TIPTOP ERP</div>\n                                    <div class="milestone-desc">ERP สถาปัตยกรรม Browser/Server แรกของเอเชีย</div>\n                                </div>\n                            </div>\n\n                            <div class="milestone above">\n                                <div class="milestone-card">\n                                    <div class="milestone-year">2001</div>\n                                    <div class="milestone-title">IPO ไต้หวัน</div>\n                                    <div class="milestone-desc">จดทะเบียนในตลาดหลักทรัพย์ไต้หวัน</div>\n                                    <span class="milestone-badge blue">TSEC</span>\n                                </div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-dot"></div>\n                            </div>\n\n                            <div class="milestone below">\n                                <div class="milestone-dot"></div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-card">\n                                    <div class="milestone-year">2006</div>\n                                    <div class="milestone-title">อันดับ 1 จีน</div>\n                                    <div class="milestone-desc">ผู้จำหน่าย ERP การผลิตอันดับ 1 ในจีน</div>\n                                </div>\n                            </div>\n\n                            <div class="milestone above">\n                                <div class="milestone-card">\n                                    <div class="milestone-year">2014</div>\n                                    <div class="milestone-title">IPO เสิ่นเจิ้น</div>\n                                    <div class="milestone-desc">จดทะเบียนในตลาดหลักทรัพย์เสิ่นเจิ้น (300378.SZ)</div>\n                                    <span class="milestone-badge blue">300378</span>\n                                </div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-dot glow"></div>\n                            </div>\n\n                            <div class="milestone below">\n                                <div class="milestone-dot"></div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-card">\n                                    <div class="milestone-year">2017</div>\n                                    <div class="milestone-title">ประเทศไทย</div>\n                                    <div class="milestone-desc">ขยายสู่อาเซียนจากกรุงเทพมหานคร</div>\n                                    <span class="milestone-badge gold">ASEAN</span>\n                                </div>\n                            </div>\n\n                            <div class="milestone above">\n                                <div class="milestone-card">\n                                    <div class="milestone-year">2020</div>\n                                    <div class="milestone-title">Foxconn ลงทุน</div>\n                                    <div class="milestone-desc">การลงทุนเชิงกลยุทธ์มูลค่า 560 ล้านหยวนจาก Foxconn FII</div>\n                                </div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-dot"></div>\n                            </div>\n\n                            <div class="milestone below">\n                                <div class="milestone-dot"></div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-card">\n                                    <div class="milestone-year">2022</div>\n                                    <div class="milestone-title">รางวัล Red Dot</div>\n                                    <div class="milestone-desc">รางวัล German Red Dot Design Award สำหรับแพลตฟอร์ม Athena</div>\n                                </div>\n                            </div>\n\n                            <div class="milestone above">\n                                <div class="milestone-card">\n                                    <div class="milestone-year">2024</div>\n                                    <div class="milestone-title">#1 PLM + MES</div>\n                                    <div class="milestone-desc">IDC อันดับ 1 ในการผลิตแบบ Discrete เริ่มเข้าอินโดนีเซีย</div>\n                                </div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-dot"></div>\n                            </div>\n\n                            <div class="milestone below">\n                                <div class="milestone-dot glow"></div>\n                                <div class="milestone-connector"></div>\n                                <div class="milestone-card">\n                                    <div class="milestone-year">2026</div>\n                                    <div class="milestone-title">ยุค AI</div>\n                                    <div class="milestone-desc">กรอบ SUPA AI ระบบอัจฉริยะสำหรับการผลิต</div>\n                                    <span class="milestone-badge green">ตอนนี้</span>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                    <div class="scroll-hint">เลื่อน →</div>\n                </div>\n            </div>\n    <script>(function(){var y=new Date().getFullYear();document.querySelectorAll(\'.dw-years\').forEach(function(e){e.textContent=y-1982})})();</script>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"สถิติ"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"สถิติ: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"สถิติ: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="stats-banner" data-particles="bold">\n    <div class="stats-banner-inner" style="position: relative; z-index: 2;">\n\n                <div class="stat-item">\n                    <div class="stat-number"><span class="dw-years">44</span>+</div>\n                    <div class="stat-description">ปีในวงการ ERP การผลิต</div>\n                </div>\n                <div class="stat-item">\n                    <div class="stat-number">50K+</div>\n                    <div class="stat-description">ลูกค้าโรงงานผลิตทั่วโลก</div>\n                </div>\n                <div class="stat-item">\n                    <div class="stat-number">100+</div>\n                    <div class="stat-description">ติดตั้งในประเทศไทย</div>\n                </div>\n                <div class="stat-item">\n                    <div class="stat-number">50+</div>\n                    <div class="stat-description">ทีมงานในประเทศไทย</div>\n                </div>\n                <div class="stat-item">\n                    <div class="stat-number white">300378</div>\n                    <div class="stat-description">จดทะเบียนตลาดหลักทรัพย์เสิ่นเจิ้น</div>\n                </div>\n            </div>\n    \n<script>\n(function(){\n  \'use strict\';\n  var reducedMotion=window.matchMedia(\'(prefers-reduced-motion: reduce)\').matches;\n  var PI2=Math.PI*2;\n  var BLUE=[0,175,240],CYAN=[0,230,255];\n  var PRESETS={\n    subtle:{frontOpacity:0.30,backOpacity:0.04,frontRadius:4.5,backRadius:0.6,color:BLUE,colorAlt:CYAN,altRatio:0.12},\n    medium:{frontOpacity:0.45,backOpacity:0.06,frontRadius:5.0,backRadius:0.8,color:BLUE,colorAlt:CYAN,altRatio:0.18},\n    bold:{frontOpacity:0.60,backOpacity:0.10,frontRadius:5.5,backRadius:1.0,color:CYAN,colorAlt:BLUE,altRatio:0.25}\n  };\n  function lerp(a,b,t){return a+(b-a)*t}\n  function DataOcean(el){\n    this.el=el;this.canvas=null;this.ctx=null;this.w=0;this.h=0;\n    this.dpr=Math.min(window.devicePixelRatio||1,2);this.visible=false;this.raf=null;this.time=0;this.resizeTimer=null;this.colors=null;\n    this.opts=this._parseOpts();this._setup();this._buildColors();this._observe();\n    if(!reducedMotion){this._loop()}else{this.visible=true;this._draw(0)}\n  }\n  DataOcean.prototype._parseOpts=function(){var n=this.el.getAttribute(\'data-particles\')||\'subtle\';if(n===\'\'||n===\'true\')n=\'subtle\';return PRESETS[n]||PRESETS.subtle};\n  DataOcean.prototype._setup=function(){\n    var c=document.createElement(\'canvas\');c.setAttribute(\'aria-hidden\',\'true\');\n    c.style.cssText=\'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;\';\n    var pos=getComputedStyle(this.el).position;if(pos===\'static\')this.el.style.position=\'relative\';\n    this.el.style.overflow=\'hidden\';this.el.insertBefore(c,this.el.firstChild);this.canvas=c;this.ctx=c.getContext(\'2d\');this._resize();\n    var self=this;window.addEventListener(\'resize\',function(){clearTimeout(self.resizeTimer);self.resizeTimer=setTimeout(function(){self._resize();self._buildColors()},200)});\n  };\n  DataOcean.prototype._resize=function(){var r=this.el.getBoundingClientRect();this.w=r.width;this.h=r.height;this.canvas.width=this.w*this.dpr;this.canvas.height=this.h*this.dpr;this.ctx.setTransform(this.dpr,0,0,this.dpr,0,0)};\n  DataOcean.prototype._buildColors=function(){var cols=Math.min(65,Math.ceil(this.w/22)+4);var rows=35;this._cols=cols;this._rows=rows;var n=cols*rows;this.colors=new Array(n);var alt=this.opts.altRatio;for(var i=0;i<n;i++){this.colors[i]=Math.random()<alt?this.opts.colorAlt:this.opts.color}};\n  DataOcean.prototype._observe=function(){var self=this;if(\'IntersectionObserver\' in window){this._obs=new IntersectionObserver(function(e){self.visible=e[0].isIntersecting},{rootMargin:\'150px 0px\'});this._obs.observe(this.el)}else{this.visible=true}};\n  DataOcean.prototype._loop=function(){var self=this;var last=0;(function tick(ts){self.raf=requestAnimationFrame(tick);if(!self.visible)return;if(ts-last<30)return;last=ts;self.time+=0.006;self._draw(self.time)})(0)};\n  DataOcean.prototype._draw=function(t){\n    var ctx=this.ctx,w=this.w,h=this.h,opts=this.opts,cols=this._cols,rows=this._rows;\n    ctx.clearRect(0,0,w,h);var ground=h+10,horizon=h*0.35,totalSpan=ground-horizon,idx=0;\n    for(var row=rows-1;row>=0;row--){\n      var depth=row/(rows-1),mappedDepth=Math.pow(depth,0.55),baseY=ground-mappedDepth*totalSpan;\n      var dotR=lerp(opts.frontRadius,opts.backRadius,depth),dotA=lerp(opts.frontOpacity,opts.backOpacity,depth);\n      var colSpacing=lerp(w/(cols-4),w/(cols+15),depth),rowShift=depth*w*0.12;\n      var waveScale=1-depth*0.75,amp1=70*waveScale,amp2=25*waveScale;\n      for(var col=0;col<cols;col++){\n        var screenX=col*colSpacing-rowShift+colSpacing*0.5;\n        if(screenX<-30||screenX>w+30){idx++;continue}\n        var worldX=col*24,worldZ=row*18;\n        var wave=amp1*Math.sin(worldX*0.0065+worldZ*0.012+t*0.9);\n        wave+=amp2*Math.sin(worldX*0.013-worldZ*0.008+t*0.55+1.8);\n        var screenY=baseY-wave;if(screenY<-15||screenY>h+15){idx++;continue}\n        var c=this.colors[idx%this.colors.length];\n        ctx.beginPath();ctx.arc(screenX,screenY,dotR,0,PI2);\n        ctx.fillStyle=\'rgba(\'+c[0]+\',\'+c[1]+\',\'+c[2]+\',\'+dotA+\')\';ctx.fill();idx++;\n      }\n    }\n  };\n  DataOcean.prototype.destroy=function(){if(this.raf)cancelAnimationFrame(this.raf);if(this._obs)this._obs.disconnect();if(this.canvas&&this.canvas.parentNode)this.canvas.parentNode.removeChild(this.canvas)};\n  function init(){var els=document.querySelectorAll(\'[data-particles]\');for(var i=0;i<els.length;i++)new DataOcean(els[i])}\n  if(document.readyState===\'loading\')document.addEventListener(\'DOMContentLoaded\',init);else init();\n})();\n</script>\n    <script>(function(){var y=new Date().getFullYear();document.querySelectorAll(\'.dw-years\').forEach(function(e){e.textContent=y-1982})})();</script>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"ผู้นำตลาด"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"ผู้นำตลาด: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"ผู้นำตลาด: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="market-leadership">\n    <div class="market-leadership-inner scroll-fade-in">\n                <div class="market-leadership-header">\n                    <span class="section-label">ได้รับการยอมรับจากผู้นำอุตสาหกรรม</span>\n                    <h2>ในภาคการผลิตของไต้หวัน</h2>\n                </div>\n                <div class="market-leadership-grid">\n\n                    <div class="market-stat-card scroll-fade-in">\n                        <div class="market-stat-value">80%</div>\n                        <div class="market-stat-label">ของ 2,000 ผู้ผลิตชั้นนำไต้หวันใช้โซลูชัน DigiWin</div>\n                    </div>\n                    <div class="market-stat-card scroll-fade-in">\n                        <div class="market-stat-value">54%</div>\n                        <div class="market-stat-label">ส่วนแบ่งตลาดโซลูชัน ERP การผลิตในไต้หวัน</div>\n                    </div>\n                    <div class="market-stat-card scroll-fade-in">\n                        <div class="market-stat-value">77%</div>\n                        <div class="market-stat-label">ของบริษัท IPO ตลาดหลักทรัพย์ไต้หวันเป็นลูกค้า DigiWin</div>\n                    </div>\n                </div>\n                <p class="market-leadership-source">แหล่งที่มา: นิตยสาร Common Wealth สำรวจเทคโนโลยีการผลิต 2023</p>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"ปรัชญา"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"ปรัชญา: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"ปรัชญา: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="beliefs-section">\n    <div class="dw-section-scene">\n                <svg aria-hidden="true" viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice">\n                    <path d="M250 200 L250 420 Q250 520 350 570 Q450 520 450 420 L450 200 L350 160Z" stroke="#000864" stroke-width="2" fill="none" opacity="0.1"/>\n                    <path d="M320 330 L345 355 L400 300" stroke="#00AFF0" stroke-width="2.5" fill="none" opacity="0.15"/>\n                    <circle cx="800" cy="200" r="60" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.08"/>\n                    <ellipse cx="800" cy="200" rx="30" ry="60" stroke="#000864" stroke-width="1" fill="none" opacity="0.06"/>\n                    <line x1="740" y1="200" x2="860" y2="200" stroke="#000864" stroke-width="1" opacity="0.06"/>\n                    <circle cx="780" cy="185" r="3" fill="#00AFF0" opacity="0.15"/>\n                    <circle cx="820" cy="210" r="3" fill="#00AFF0" opacity="0.12"/>\n                    <circle cx="795" cy="225" r="2.5" fill="#00AFF0" opacity="0.1"/>\n                    <line x1="100" y1="700" x2="600" y2="700" stroke="#000864" stroke-width="1" opacity="0.08"/>\n                    <line x1="100" y1="690" x2="100" y2="710" stroke="#000864" stroke-width="1" opacity="0.08"/>\n                    <line x1="350" y1="690" x2="350" y2="710" stroke="#000864" stroke-width="1" opacity="0.08"/>\n                    <line x1="600" y1="690" x2="600" y2="710" stroke="#000864" stroke-width="1" opacity="0.08"/>\n                    <text x="100" y="730" font-family="\'Noto Sans\',sans-serif" font-size="10" fill="#000864" opacity="0.06" text-anchor="middle">1982</text>\n                    <text x="350" y="730" font-family="\'Noto Sans\',sans-serif" font-size="10" fill="#000864" opacity="0.06" text-anchor="middle">2006</text>\n                    <text x="600" y="730" font-family="\'Noto Sans\',sans-serif" font-size="10" fill="#000864" opacity="0.06" text-anchor="middle">2026</text>\n                    <rect x="1050" y="400" width="200" height="120" rx="8" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.08"/>\n                    <line x1="1070" y1="440" x2="1230" y2="440" stroke="#000864" stroke-width="0.5" opacity="0.06"/>\n                    <line x1="1070" y1="460" x2="1200" y2="460" stroke="#000864" stroke-width="0.5" opacity="0.06"/>\n                    <line x1="1070" y1="480" x2="1210" y2="480" stroke="#000864" stroke-width="0.5" opacity="0.06"/>\n                    <text x="1150" y="420" font-family="\'Noto Sans\',sans-serif" font-size="9" font-weight="700" fill="#000864" opacity="0.06" text-anchor="middle">VALUES</text>\n                    <circle cx="650" cy="450" r="3" fill="#000864" opacity="0.06"/>\n                    <circle cx="1300" cy="300" r="4" fill="#000864" opacity="0.05"/>\n                    <circle cx="150" cy="500" r="3" fill="#00AFF0" opacity="0.08"/>\n                </svg>\n            </div>\n            <div class="beliefs-inner">\n                <div class="beliefs-header">\n                    <span class="section-label">ปรัชญาของเรา</span>\n                    <h2>สิ่งที่เราเชื่อ</h2>\n                </div>\n                <div class="beliefs-grid">\n\n                    <div class="belief-card">\n                        <div class="belief-number">BELIEF 01</div>\n                        <h3>"การผลิตไม่ใช่เรื่องทั่วไป"</h3>\n                        <p>เราไม่ขายให้ธนาคาร ห้างค้าปลีก หรือโรงพยาบาล เราให้บริการเฉพาะภาคการผลิตเพราะพื้นที่หน้างานต้องการสิ่งนี้ BOM, Routing, Work Order, OEE—สิ่งเหล่านี้ไม่ใช่ฟีเจอร์ที่เราเพิ่มเข้ามา แต่เป็นเหตุผลที่เราดำรงอยู่</p>\n                    </div>\n                    <div class="belief-card">\n                        <div class="belief-number">BELIEF 02</div>\n                        <h3>"เติบโตไปด้วยกัน ไม่ใช่แยกจากกัน"</h3>\n                        <p>ผลิตภัณฑ์ของเรา—iGP → T100 → MES → WMS → AIoT—หมายความว่าพันธมิตร ERP ของคุณไม่เปลี่ยนเมื่อธุรกิจขยายตัว การลงทุนของคุณสะสมมูลค่า ไม่มีวันรีเซ็ต จากโรงงาน 20 คนสู่กลุ่มบริษัทหลายไซต์</p>\n                    </div>\n                    <div class="belief-card">\n                        <div class="belief-number">BELIEF 03</div>\n                        <h3>"รากฐานท้องถิ่น มาตรฐานระดับโลก"</h3>\n                        <p>ทีมไทยของเราพูดภาษาไทย เข้าใจวัฒนธรรมธุรกิจไทย และมีประสบการณ์ระดับโลก 44 ปีหนุนหลัง เราไม่ใช่ผู้จำหน่ายระยะไกลที่ส่งที่ปรึกษาจากต่างประเทศ—เราอยู่ที่นี่</p>\n                    </div>\n                    <div class="belief-card">\n                        <div class="belief-number">BELIEF 04</div>\n                        <h3>"ข้อมูลควรปลดปล่อย ไม่ใช่ซับซ้อน"</h3>\n                        <p>เราเปลี่ยนความวุ่นวายในโรงงาน—Excel ลับ สต๊อกผี ระบบที่ไม่เชื่อมต่อ—ให้เป็นข้อมูลเชิงปฏิบัติที่ชัดเจน ผู้จัดการฝ่ายผลิตไม่ควรต้องเปิด 3 Spreadsheet เพื่อตอบคำถามง่ายๆ</p>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"ผลลัพธ์"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"ผลลัพธ์: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"ผลลัพธ์: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="outcomes-section">\n    <div class="outcomes-inner">\n                <div class="outcomes-visual">\n                    <div class="outcomes-image">\n                        <img src="/wp-content/uploads/2026/02/about-outcomes.jpg" alt="ทีมงานร่วมกันทำงานในพื้นที่ผลิตสมัยใหม่" loading="lazy">\n                    </div>\n                </div>\n                <div class="outcomes-content">\n                    <h2>เพราะ DigiWin <span>คุณสามารถ...</span></h2>\n\n                    <div class="outcome-item">\n                        <div class="outcome-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><circle cx="12" cy="12" r="10"/><path d="M12 6v6l4 2"/></svg>\n                        </div>\n                        <div class="outcome-text">\n                            <h3>มองเห็นโรงงานแบบ Real-time</h3>\n                            <p>MES และ AIoT ให้ข้อมูลการผลิตแบบสด ไม่ใช่ Spreadsheet ของเมื่อวาน รู้ว่าเกิดอะไรขึ้นตอนนี้ ไม่ใช่สิ่งที่เกิดขึ้นกะที่แล้ว</p>\n                        </div>\n                    </div>\n\n                    <div class="outcome-item">\n                        <div class="outcome-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><path d="M12 2v20M17 5H9.5a3.5 3.5 0 000 7h5a3.5 3.5 0 010 7H6"/></svg>\n                        </div>\n                        <div class="outcome-text">\n                            <h3>ควบคุมต้นทุนก่อนที่ต้นทุนจะควบคุมคุณ</h3>\n                            <p>ติดตามวัตถุดิบ ลดของเสีย เพิ่มประสิทธิภาพ Yield ในทุก Production Run เห็นความสูญเปล่าก่อนที่จะกลายเป็นขาดทุน</p>\n                        </div>\n                    </div>\n\n                    <div class="outcome-item">\n                        <div class="outcome-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><path d="M5 12h14M12 5l7 7-7 7"/></svg>\n                        </div>\n                        <div class="outcome-text">\n                            <h3>ส่งมอบตรงเวลา ทุกครั้ง</h3>\n                            <p>ระบบจัดตาราง Production และ WMS (ระบบจัดการคลังสินค้า) ทำงานร่วมกัน เพื่อรักษาคำมั่นสัญญาการส่งมอบ ไม่มีความวุ่นวายจากการเร่งงานอีกต่อไป</p>\n                        </div>\n                    </div>\n\n                    <div class="outcome-item">\n                        <div class="outcome-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><path d="M21 16V8a2 2 0 00-1-1.73l-7-4a2 2 0 00-2 0l-7 4A2 2 0 003 8v8a2 2 0 001 1.73l7 4a2 2 0 002 0l7-4A2 2 0 0021 16z"/></svg>\n                        </div>\n                        <div class="outcome-text">\n                            <h3>ขยายธุรกิจโดยไม่ต้องเริ่มใหม่</h3>\n                            <p>ระบบนิเวศเดียวจากโรงงานเล็กสู่กลุ่มบริษัท เพิ่ม MES เมื่อพร้อม เพิ่ม WMS เมื่อต้องการ รากฐานของคุณยังแข็งแกร่ง</p>\n                        </div>\n                    </div>\n\n                    <div class="outcome-item">\n                        <div class="outcome-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><path d="M22 11.08V12a10 10 0 11-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>\n                        </div>\n                        <div class="outcome-text">\n                            <h3>ผ่านการตรวจ BOI อย่างมั่นใจ</h3>\n                            <p>การกระทบยอดวัตถุดิบระดับใบสั่งผลิตที่ผ่านการตรวจสอบจาก BOI ลูกค้ารายหนึ่งประหยัดภาษีเพิ่มเติมได้มากกว่า 10 ล้านบาทต่อปี ผ่านการรับรองจากกรมสรรพากร พร้อมระบบตรวจสอบย้อนกลับครบวงจร</p>\n                        </div>\n                    </div>\n\n                    <div class="outcome-item">\n                        <div class="outcome-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><path d="M2 3h6a4 4 0 014 4v14a3 3 0 00-3-3H2zM22 3h-6a4 4 0 00-4 4v14a3 3 0 013-3h7z"/></svg>\n                        </div>\n                        <div class="outcome-text">\n                            <h3>ตัดสินใจอย่างมั่นใจ</h3>\n                            <p>แดชบอร์ด BI (Business Intelligence) และการวิเคราะห์ที่เปลี่ยนข้อมูลดิบเป็นข้อมูลเชิงกลยุทธ์ที่ชัดเจน มองเห็นรูปแบบ ไม่ใช่แค่ตัวเลข</p>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"ประเทศไทย"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"ประเทศไทย: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"ประเทศไทย: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="thailand-section">\n    <div class="thailand-inner" style="position: relative; z-index: 2;">\n                <div class="thailand-header">\n                    <span class="section-label">พิสูจน์แล้วในเพื่อนบ้านของคุณ</span>\n                    <h2>ความมุ่งมั่นต่อประเทศไทย</h2>\n                    <p>สนับสนุนจริง ไม่ต้องแปลภาษา คุณไม่ใช่ "หนูทดลอง"</p>\n                </div>\n                <div class="thailand-content">\n                    <div class="thailand-text">\n                        <div class="thailand-proof-grid">\n\n                            <div class="thailand-proof">\n                                <span class="proof-number">100+</span>\n                                <span class="proof-text">ลูกค้าและพันธมิตรในประเทศไทย</span>\n                            </div>\n                            <div class="thailand-proof">\n                                <span class="proof-number">50+</span>\n                                <span class="proof-text">ทีมงานคนไทย</span>\n                            </div>\n                            <div class="thailand-proof">\n                                <span class="proof-number">60%+</span>\n                                <span class="proof-text">สองภาษา (ไทย + จีน)</span>\n                            </div>\n                            <div class="thailand-proof">\n                                <span class="proof-number">ตั้งแต่ 2017</span>\n                                <span class="proof-text">ให้บริการผู้ผลิตไทย</span>\n                            </div>\n                        </div>\n\n                        <p style="font-size: 15px; color: #475569; line-height: 1.8; margin: 24px 0;">DigiWin เข้าสู่ประเทศไทยในปี 2017 โดยเริ่มให้บริการผู้ผลิตไต้หวันและจีนที่ตั้งฐานการผลิตที่นี่ เมื่อความต้องการเพิ่มขึ้น เราจดทะเบียนบริษัทไทยอย่างเป็นทางการในปี 2019 และสร้างทีมท้องถิ่นตั้งแต่เริ่มต้น—จ้างที่ปรึกษาคนไทย เรียนรู้วัฒนธรรมธุรกิจไทย และสร้างความสัมพันธ์กับเจ้าของโรงงานไทย วันนี้ เราให้บริการตลาดท้องถิ่นโดยตรงด้วยทีมงานกว่า 50+ คน เราไม่ใช่ผู้จำหน่ายระยะไกลที่ส่งที่ปรึกษาจากต่างประเทศ เราเป็นเพื่อนบ้านของคุณ</p>\n\n                        <h3>ลูกค้าอ้างอิงในไทย</h3>\n                        <p class="reference-intro">สภาพแวดล้อมการผลิตที่ใช้งานจริงบนระบบของเราในปัจจุบัน:</p>\n                        <div class="reference-logos">\n                            <span class="reference-name">GoldenSea Sanki</span>\n                            <span class="reference-name">Top Mould</span>\n                            <span class="reference-name">Accauto</span>\n                            <span class="reference-name">Unique New Energy</span>\n                            <span class="reference-name">Intensive Mould</span>\n                        </div>\n\n                        <h3>พร้อมรองรับกฎหมายไทย</h3>\n                        <ul class="thailand-highlights">\n\n                            <li>\n                                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="20 6 9 17 4 12"/></svg>\n                                <span><strong>ผ่านการรับรองจากกรมสรรพากร</strong></span>\n                            </li>\n                            <li>\n                                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="20 6 9 17 4 12"/></svg>\n                                <span>ระบบภาษีหัก ณ ที่จ่ายในตัว</span>\n                            </li>\n                            <li>\n                                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="20 6 9 17 4 12"/></svg>\n                                <span>พร้อมเชื่อมต่อ e-Tax</span>\n                            </li>\n                            <li>\n                                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="20 6 9 17 4 12"/></svg>\n                                <span>รองรับการรายงาน BOI</span>\n                            </li>\n                        </ul>\n                    </div>\n                    <div class="contact-card">\n                        <h3>สำนักงานประเทศไทย</h3>\n                        <div class="contact-item">\n                            <div class="contact-label">ที่อยู่</div>\n                            <div class="contact-value">เลขที่ 2/117-118 อาคาร Bangna Complex Office Tower,<br>ชั้น 22 ถนนเทพารักษ์,<br>บางนา กรุงเทพฯ 10260</div>\n                        </div>\n                        <div class="contact-item">\n                            <div class="contact-label">อีเมล</div>\n                            <div class="contact-value"><a href="mailto:info@digiwin.co.th">info@digiwin.co.th</a></div>\n                        </div>\n                        <a href="/contact/" class="contact-cta">ติดต่อเรา →</a>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Asia Presence"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Asia Presence: Row"}}},"decoration":{"layout":{"desktop":{"value