ss="region-title">ASEAN</span>\n                                    <span class="region-badge">อีก 3 ประเทศ</span>\n                                </div>\n                                <div class="asean-countries">\n                                    <div class="asean-country">\n                                        <span class="country-flag"><svg width="24" height="18" viewBox="0 0 24 18" fill="none" xmlns="http://www.w3.org/2000/svg"><rect width="24" height="18" rx="2" fill="#DA251D"/><path d="M12 3l1.8 5.4L8.4 5.4h7.2l-5.4 3L12 3z" fill="#FFFF00"/></svg></span>\n                                        <span class="country-name">胡志明市 Ho Chi Minh City</span>\n                                        <span class="country-year">Since 2008</span>\n                                    </div>\n                                    <div class="asean-country">\n                                        <span class="country-flag"><svg width="24" height="18" viewBox="0 0 24 18" fill="none" xmlns="http://www.w3.org/2000/svg"><rect width="24" height="18" rx="2" fill="#fff"/><rect width="24" height="1.3" fill="#CC0001"/><rect y="2.6" width="24" height="1.3" fill="#CC0001"/><rect y="5.2" width="24" height="1.3" fill="#CC0001"/><rect y="7.8" width="24" height="1.3" fill="#CC0001"/><rect y="10.4" width="24" height="1.3" fill="#CC0001"/><rect y="13" width="24" height="1.3" fill="#CC0001"/><rect y="15.6" width="24" height="2.4" fill="#CC0001"/><rect width="14" height="10.4" fill="#010066"/><circle cx="5.5" cy="5.2" r="3" fill="#FC0"/><circle cx="6.5" cy="5.2" r="2.5" fill="#010066"/><path d="M9 3.5l.5 1.5-.9-.8h1.3l-1.2.8z" fill="#FC0"/></svg></span>\n                                        <span class="country-name">吉隆坡 Kuala Lumpur</span>\n                                        <span class="country-year">Since 2013</span>\n                                    </div>\n                                    <div class="asean-country">\n                                        <span cla