               <div class="presence-stat">\n                            <div class="presence-stat-value">5,500+</div>\n                            <div class="presence-stat-label">พนักงาน</div>\n                        </div>\n                        <div class="presence-stat">\n                            <div class="presence-stat-value">4</div>\n                            <div class="presence-stat-label">ประเทศในอาเซียน</div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"รางวัล"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"รางวัล: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"รางวัล: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="awards-section">\n    <div class="dw-section-scene">\n                <svg aria-hidden="true" viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice">\n                    <circle cx="300" cy="300" r="55" stroke="#000864" stroke-width="2" fill="none" opacity="0.1"/>\n                    <circle cx="300" cy="300" r="42" stroke="#000864" stroke-width="1" fill="none" opacity="0.07"/>\n                    <path d="M280 300 L295 315 L330 280" stroke="#00AFF0" stroke-width="2" fill="none" opacity="0.15"/>\n                    <circle cx="800" cy="250" r="50" stroke="#000864" stroke-width="2" fill="none" opacity="0.1"/>\n                    <circle cx="800" cy="250" r="38" stroke="#000864" stroke-width="1" fill="none" opacity="0.07"/>\n                    <text x="800" y="255" font-family="\'Noto Sans\',sans-serif" font-size="10" font-weight="700" fill="#000864" opacity="0.08" text-anchor="middle">ISO</text>\n                    <circle cx="1150" cy="350" r="45" stroke="#000864" stroke-width="2" fill="none" opacity="0.1"/>\n                    <circle cx="1150" cy="350" r="33" stroke="#000864" stroke-width="1" fill="none" opacity="0.07"/>\n                    <path d="M1138 320 L1150 305 L1162 320" stroke="#00AFF0" stroke-width="1.5" fill="none" opacity="0.12"/>\n                    <line x1="100" y1="650" x2="1300" y2="650" stroke="#000864" stroke-width="1.5" opacity="0.08"/>\n                    <line x1="100" y1="640" x2="100" y2="660" stroke="#000864" stroke-width="1.5" opacity="0.08"/>\n                    <line x1="400" y1="640" x2="400" y2="660" stroke="#000864" stroke-width="1.5" opacity="0.08"/>\n                    <line x1="700" y1="640" x2="700" y2="660" stroke="#000864" stroke-width="1.5" opacity="0.08"/>\n                    <line x1="1000" y1="640" x2="1000" y2="660" stroke="#000864" stroke-width="1.5" opacity="0.08"/>\n                    <line x1="1300" y1="640" x2="1300" y2="660" stroke="#000864" stroke-width="1.5" opacity="0.08"/>\n                    <text x="100" y="680" font-family="\'Noto Sans\',sans-serif" font-size="10" fill="#000864" opacity="0.06" text-anchor="middle">1996</text>\n                    <text x="700" y="680" font-family="\'Noto Sans\',sans-serif" font-size="10" fill="#000864" opacity="0.06" text-anchor="middle">2010</text>\n                    <text x="1300" y="680" font-family="\'Noto Sans\',sans-serif" font-size="10" fill="#000864" opacity="0.06" text-anchor="middle">2025</text>\n                    <path d="M500 500 L500 480 L520 480" stroke="#000864" stroke-width="1" fill="none" opacity="0.08"/>\n                    <path d="M900 550 L920 550 L920 530" stroke="#000864" stroke-width="1" fill="none" opacity="0.08"/>\n                    <circle cx="600" cy="400" r="3" fill="#000864" opacity="0.06"/>\n                    <circle cx="1050" cy="550" r="4" fill="#00AFF0" opacity="0.06"/>\n                    <circle cx="200" cy="550" r="3" fill="#000864" opacity="0.05"/>\n                </svg>\n            </div>\n            <div class="awards-inner">\n                <div class="awards-header">\n                    <span class="section-label">การรับรองจากบุคคลภายนอก</span>\n                    <h2>รางวัลและการยอมรับ</h2>\n                    <p>นักวิเคราะห์อุตสาหกรรมและหน่วยงานรับรองยืนยันสิ่งที่ลูกค้าของเรารู้อยู่แล้ว</p>\n                </div>\n\n                <div class="awards-grid">\n\n                    <div class="award-card">\n                        <div class="award-icon gold">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><circle cx="12" cy="8" r="6"/><path d="M15.477 12.89L17 22l-5-3-5 3 1.523-9.11"/></svg>\n                        </div>\n                        <div class="award-year">2022</div>\n                        <h3>รางวัล German Red Dot Design</h3>\n                        <p>แพลตฟอร์ม Digiwin Athena ได้รับการยอมรับด้านการออกแบบซอฟต์แวร์อุตสาหกรรมที่สร้างสรรค์</p>\n                    </div>\n\n                    <div class="award-card">\n                        <div class="award-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"/></svg>\n                        </div>\n                        <div class="award-year">2024-2025</div>\n                        <h3>#1 PLM + MES ส่วนแบ่งตลาด</h3>\n                        <p>จัดอันดับโดย IDC: ส่วนแบ่งตลาด 32% ในการผลิตแบบ Discrete ติดต่อกัน 3 ปี</p>\n                    </div>\n\n                    <div class="award-card">\n                        <div class="award-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><path d="M22 11.08V12a10 10 0 11-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>\n                        </div>\n                        <div class="award-year">2010</div>\n                        <h3>CMMI Level 4</h3>\n                        <p>กระบวนการซอฟต์แวร์ระดับ Quantitatively Managed—คุณสมบัติหายากสำหรับผู้จำหน่าย ERP</p>\n                    </div>\n\n                    <div class="award-card">\n                        <div class="award-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><rect x="3" y="11" width="18" height="11" rx="2"/><path d="M7 11V7a5 5 0 0110 0v4"/></svg>\n                        </div>\n                        <div class="award-year">1996–2025</div>\n                        <h3>ISO 9001 & 27001</h3>\n                        <p>การรับรองคุณภาพและความปลอดภัยข้อมูลอย่างต่อเนื่องเป็นเวลา 29 ปี</p>\n                    </div>\n\n                    <div class="award-card">\n                        <div class="award-icon gold">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/></svg>\n                        </div>\n                        <div class="award-year">2013</div>\n                        <h3>รางวัลนวัตกรรมอุตสาหกรรมแห่งชาติ</h3>\n                        <p>ได้รับการยอมรับจากกระทรวงเศรษฐกิจไต้หวันสำหรับการมีส่วนร่วมต่ออุตสาหกรรม</p>\n                    </div>\n\n                    <div class="award-card">\n                        <div class="award-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><path d="M21 16V8a2 2 0 00-1-1.73l-7-4a2 2 0 00-2 0l-7 4A2 2 0 003 8v8a2 2 0 001 1.73l7 4a2 2 0 002 0l7-4A2 2 0 0021 16z"/><polyline points="7.5 4.21 12 6.81 16.5 4.21"/><polyline points="7.5 19.79 7.5 14.6 3 12"/><polyline points="21 12 16.5 14.6 16.5 19.79"/><polyline points="3.27 6.96 12 12.01 20.73 6.96"/><line x1="12" y1="22.08" x2="12" y2="12"/></svg>\n                        </div>\n                        <div class="award-year">2024</div>\n                        <h3>โซลูชัน Industrial Internet ดีเด่น</h3>\n                        <p>การยอมรับหมวด PLM สำหรับนวัตกรรมการผลิตอัจฉริยะ</p>\n                    </div>\n\n                    <div class="award-card">\n                        <div class="award-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><circle cx="12" cy="12" r="10"/><path d="M8 14s1.5 2 4 2 4-2 4-2M9 9h.01M15 9h.01"/></svg>\n                        </div>\n                        <div class="award-year">1992</div>\n                        <h3>รางวัลซอฟต์แวร์ ERP แรกของไต้หวัน</h3>\n                        <p>รางวัลซอฟต์แวร์ดีเด่น Information Month—การยอมรับจากอุตสาหกรรมครั้งแรกของเรา</p>\n                    </div>\n\n                    <div class="award-card">\n                        <div class="award-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" stroke-width="2"><path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 00-3-3.87M16 3.13a4 4 0 010 7.75"/></svg>\n                        </div>\n                        <div class="award-year">2020</div>\n                        <h3>Foxconn ลงทุนเชิงกลยุทธ์</h3>\n                        <p>560 ล้านหยวนจากผู้ผลิตอิเล็กทรอนิกส์รายใหญ่ที่สุดของโลก ยืนยันเทคโนโลยีของเรา</p>\n                    </div>\n                </div>\n\n                <div class="certifications-bar">\n\n                    <div class="cert-item">\n                        <div class="cert-badge">ISO 27001</div>\n                        <div class="cert-label">ความปลอดภัยข้อมูล</div>\n                    </div>\n                    <div class="cert-item">\n                        <div class="cert-badge">ISO 9001</div>\n                        <div class="cert-label">การจัดการคุณภาพ</div>\n                    </div>\n                    <div class="cert-item">\n                        <div class="cert-badge">CMMI L4</div>\n                        <div class="cert-label">วุฒิภาวะกระบวนการ</div>\n                    </div>\n                    <div class="cert-item">\n                        <div class="cert-badge">Thai RD</div>\n                        <div class="cert-label">ผ่านการรับรองกรมสรรพากร</div>\n                    </div>\n                    <div class="cert-item">\n                        <div class="cert-badge">300378.SZ</div>\n                        <div class="cert-label">จดทะเบียนเสิ่นเจิ้น</div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: พร้อมทำงานกับทีมที่เข้าใจการผลิต"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: พร้อมทำงานกับทีมที่เข้าใจการผลิต: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: พร้อมทำงานกับทีมที่เข้าใจการผลิต: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="about-cta-section">\n    <div class="about-cta-super-d" aria-hidden="true"></div>\n    <div class="about-cta-wave-flow" aria-hidden="true"></div>\n    <div class="about-cta-container">\n      <h2 class="about-cta-title">พร้อมทำงานกับทีมที่เข้าใจการผลิตจริงๆ หรือยัง?</h2>\n      <p class="about-cta-subtitle">ดูว่าประสบการณ์ <span class="dw-years">44</span> ปีด้านการผลิต—ได้รับการสนับสนุนจาก Foxconn FII—สามารถช่วยให้คุณแข่งขันบนเวทีระดับโลกได้อย่างไร</p>\n      <div class="about-cta-btn-row">\n        <a href="/demo.html" class="about-cta-btn about-cta-btn--primary">พูดคุยกับเรา</a>\n        <a href="/partner-program.html" class="about-cta-btn about-cta-btn--ghost">เป็นพันธมิตร</a>\n      </div>\n    <div class="about-cta-contact-info"><div class="about-cta-contact-item"><svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg><span>เลขที่ 2/117-118 อาคาร Bangna Complex Office Tower, ชั้น 22, ถ.เทพารักษ์, บางนา, กรุงเทพฯ 10260</span></div><div class="about-cta-contact-item"><svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z"/><polyline points="22,6 12,13 2,6"/></svg><a href="mailto:info@digiwin.co.th">info@digiwin.co.th</a></div></div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100785;

