INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100785, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === HERO (S1) === */\n/* TODO: Review and remap class selectors to use hero prefix */\n/* TODO: Add section container: .hero-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n.about-hero {\n            background: linear-gradient(135deg, #000432 0%, #000864 50%, #001080 100%);\n            padding: 140px 24px 100px;\n            position: relative;\n            overflow: hidden;\n        }\n.about-hero::before {\n            content: \'\';\n            position: absolute;\n            inset: 0;\n            background-image: url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");\n            pointer-events: none;\n        }\n.about-hero-inner {\n            max-width: 1200px;\n            margin: 0 auto;\n            position: relative;\n            z-index: 1;\n            display: grid;\n            grid-template-columns: 1fr 1fr;\n            gap: 80px;\n            align-items: center;\n        }\n.about-hero-content h1 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: clamp(36px, 5vw, 52px);\n            font-weight: 700;\n            color: #fff;\n            line-height: 1.15;\n            margin-bottom: 24px;\n        }\n.about-hero-content h1 span {\n            color: #00AFF0;\n        }\n.about-hero-content p {\n            font-size: 18px;\n            color: rgba(255,255,255,0.85);\n            line-height: 1.7;\n            margin-bottom: 24px;\n        }\n.hero-scroll-cta {\n            display: inline-flex;\n            align-items: center;\n            gap: 8px;\n            color: #00AFF0;\n            font-weight: 600;\n            font-size: 15px;\n            text-decoration: none;\n            transition: all 0.3s ease;\n        }\n.hero-scroll-cta:hover {\n            gap: 12px;\n        }\n.hero-scroll-cta svg {\n            width: 20px;\n            height: 20px;\n            stroke: currentColor;\n            animation: bounce-down 2s ease-in-out infinite;\n        }\n@keyframes bounce-down {\n            0%, 100% { transform: translateY(0); }\n            50% { transform: translateY(6px); }\n        }\n.about-hero-stats {\n            display: grid;\n            grid-template-columns: repeat(2, 1fr);\n            gap: 24px;\n        }\n.hero-stat {\n            background: rgba(255,255,255,0.05);\n            border: 1px solid rgba(255,255,255,0.1);\n            border-radius: 16px;\n            padding: 32px;\n            text-align: center;\n        }\n.hero-stat-value {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 48px;\n            font-weight: 700;\n            color: #00AFF0;\n            line-height: 1;\n            margin-bottom: 8px;\n        }\n.hero-stat-label {\n            font-size: 14px;\n            color: rgba(255,255,255,0.75);\n        }\n@media (max-width: 1024px) {\n  .about-hero-inner{grid-template-columns:1fr;gap:48px}\n  .about-hero-stats{max-width:400px;margin:0 auto}\n}\n@media (max-width: 768px) {\n  .hero-scroll-cta{min-height:44px}\n}\n@media (max-width: 640px) {\n  .about-hero{padding:120px 20px 80px}\n  .about-hero-content h1{font-size:28px}\n  .about-hero-stats{grid-template-columns:1fr}\n}\n\n/* Divi overrides */\n.et_pb_section .about-hero-content h1{font-weight:700 !important;line-height:1.15 !important}\n.et_pb_section .about-hero-content p{padding-bottom:0 !important;line-height:30.6px !important}\n.et_pb_section .hero-stat-value{line-height:48px !important;color:#00AFF0 !important}\n.et_pb_section .hero-stat-label{line-height:22.4px !important}\n\n/* Defensive SVG sizing */\nsvg:not([width]):not([class]){max-width:48px;max-height:48px}\n@media(prefers-reduced-motion:reduce){}\n\n/* Super D decoration — unique class to avoid cascade conflict with other sections\' dw-d-bg */\n.hero-deco{position:absolute;top:50%;right:auto;left:-15%;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center left;background-size:contain;transform:translateY(-50%);opacity:0.16;pointer-events:none;z-index:0}\n/* === MISSION (S2) === */\n.mission-section {\n            padding: 100px 24px;\n            background: #fff;\n            -webkit-font-smoothing: auto;\n            -moz-osx-font-smoothing: auto;\n        }\n.mission-inner {\n            max-width: 1100px;\n            margin: 0 auto;\n            display: grid;\n            grid-template-columns: 1.2fr 1fr;\n            gap: 80px;\n            align-items: center;\n        }\n.mission-content h2 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 36px;\n            font-weight: 700;\n            color: #000864;\n            margin-bottom: 32px;\n            line-height: 1.2;\n        }\n.mission-content h2 span {\n            color: #0369a1;\n        }\n.mission-content p {\n            font-size: 17px;\n            color: #475569;\n            line-height: 1.8;\n            margin-bottom: 24px;\n        }\n.mission-origin {\n            background: linear-gradient(135deg, #eff6ff, #dbeafe);\n            border-left: 4px solid #00AFF0;\n            padding: 24px 28px;\n            border-radius: 0 12px 12px 0;\n            margin-top: 32px;\n        }\n.mission-origin-chinese {\n            font-family: \'Noto Sans TC\', sans-serif;\n            font-size: 32px;\n            font-weight: 700;\n            color: #000864;\n            margin-bottom: 8px;\n            line-height: 51.2px;\n        }\n.mission-origin-pinyin {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 14px;\n            color: #5b6b80;\n            margin-bottom: 12px;\n            line-height: 22.4px;\n        }\n.mission-origin-meaning {\n            font-size: 15px;\n            color: #475569;\n            font-style: italic;\n        }\n.mission-visual {\n            position: relative;\n        }\n.mission-image {\n            width: 100%;\n            height: 400px;\n            border-radius: 24px;\n            overflow: hidden;\n            position: relative;\n        }\n.mission-image img {\n            width: 100%;\n            height: 100%;\n            object-fit: cover;\n        }\n@media (max-width: 1024px) {\n  .mission-inner{grid-template-columns:1fr;gap:48px}\n}\n@media (max-width: 640px) {\n  .mission-image{height:280px}\n  .mission-content h2{font-size:28px}\n}\n\n/* Divi overrides */\n.et_pb_section .mission-content h2{font-weight:700 !important;line-height:1.2 !important}\n.et_pb_section .mission-content p{padding-bottom:0 !important;line-height:30.6px !important}\n.et_pb_section .mission-origin-meaning{line-height:24px !important;padding-bottom:0 !important}\n\n@media(prefers-reduced-motion:reduce){}\n\n/* Super D decoration */\n.dw-d-bg{position:absolute;top:50%;right:auto;left:50%;width:80%;min-height:80vh;background:url("data:image/svg+xml;base64,") no-repeat center center;background-size:contain;transform:translate(-50%, -50%);opacity:0.06;pointer-events:none;z-index:0}\n/* === TIMELINE (S3) === */\n/* TODO: Review and remap class selectors to use tim prefix */\n/* TODO: Add section container: .timeline-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n.timeline-section {\n            padding: 80px 24px;\n            background: linear-gradient(180deg, #000864 0%, #000432 100%);\n            position: relative;\n            overflow: hidden;\n        }\n.timeline-section::before {\n            content: \'\';\n            position: absolute;\n            inset: 0;\n            background-image: url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");\n            pointer-events: none;\n        }\n.timeline-inner {\n            max-width: 1200px;\n            margin: 0 auto;\n            position: relative;\n            z-index: 1;\n        }\n.timeline-header {\n            text-align: center;\n            margin-bottom: 48px;\n        }\n.section-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 12px;\n            font-weight: 500;\n            color: #00AFF0;\n            letter-spacing: 2px;\n            text-transform: uppercase;\n            margin-bottom: 16px;\n            display: block;\n        }\n.timeline-header h2 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 36px;\n            font-weight: 700;\n            color: #fff;\n            margin-bottom: 12px;\n        }\n.timeline-header p {\n            font-size: 16px;\n            color: rgba(255,255,255,0.75);\n            max-width: 550px;\n            margin: 0 auto;\n        }\n.timeline-scroll-container {\n            position: relative;\n            overflow: hidden;\n        }\n.timeline-scroll-container::before,\n        .timeline-scroll-container::after {\n            content: \'\';\n            position: absolute;\n            top: 0;\n            bottom: 0;\n            width: 60px;\n            z-index: 2;\n            pointer-events: none;\n        }\n.timeline-scroll-container::before {\n            left: 0;\n            background: linear-gradient(90deg, #000432 0%, transparent 100%);\n        }\n.timeline-scroll-container::after {\n            right: 0;\n            background: linear-gradient(-90deg, #000432 0%, transparent 100%);\n        }\n.timeline-rail-wrapper {\n            overflow-x: auto;\n            scroll-snap-type: x mandatory;\n            -webkit-overflow-scrolling: touch;\n            scrollbar-width: none;\n        }\n.timeline-rail-wrapper::-webkit-scrollbar {\n            display: none;\n        }\n.timeline-rail {\n            display: flex;\n            align-items: center;\n            gap: 12px;\n            padding: 180px 100px;\n            min-width: max-content;\n            position: relative;\n        }\n.timeline-rail::before {\n            content: \'\';\n            position: absolute;\n            top: 50%;\n            left: 0;\n            right: 0;\n            height: 2px;\n            background: linear-gradient(90deg, transparent 0%, rgba(0,175,240,0.15) 5%, rgba(0,175,240,0.4) 50%, rgba(0,175,240,0.15) 95%, transparent 100%);\n            transform: translateY(-50%);\n        }\n.milestone {\n            scroll-snap-align: center;\n            display: flex;\n            flex-direction: column;\n            align-items: center;\n            position: relative;\n            flex-shrink: 0;\n            width: 180px;\n        }\n.milestone.above .milestone-card {\n            position: absolute;\n            bottom: calc(50% + 28px);\n            left: 50%;\n            transform: translateX(-50%);\n        }\n.milestone.above .milestone-dot {\n            position: relative;\n            z-index: 1;\n        }\n.milestone.above .milestone-connector {\n            position: absolute;\n            bottom: calc(50% + 7px);\n            width: 2px;\n            height: 24px;\n            background: rgba(0,175,240,0.3);\n        }\n.milestone.below .milestone-card {\n            position: absolute;\n            top: calc(50% + 28px);\n            left: 50%;\n            transform: translateX(-50%);\n        }\n.milestone.below .milestone-connector {\n            position: absolute;\n            top: calc(50% + 7px);\n            width: 2px;\n            height: 24px;\n            background: rgba(0,175,240,0.3);\n        }\n.milestone-dot {\n            width: 14px;\n            height: 14px;\n            background: #000864;\n            border: 3px solid #00AFF0;\n            border-radius: 50%;\n            position: relative;\n            z-index: 1;\n            flex-shrink: 0;\n        }\n.milestone-dot.glow {\n            background: #00AFF0;\n            box-shadow: 0 0 0 6px rgba(0,175,240,0.2);\n        }\n.milestone-card {\n            background: rgba(255,255,255,0.04);\n            border: 1px solid rgba(255,255,255,0.08);\n            border-radius: 12px;\n            padding: 14px 16px;\n            width: 170px;\n            transition: all 0.3s ease;\n        }\n.milestone-card:hover {\n            background: rgba(255,255,255,0.08);\n            border-color: rgba(0,175,240,0.3);\n            transform: translateX(-50%);\n        }\n.milestone-year {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 14px;\n            font-weight: 600;\n            color: #0369a1;\n            margin-bottom: 6px;\n        }\n.milestone-title {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 14px;\n            font-weight: 600;\n            color: rgba(255,255,255,0.95);\n            margin-bottom: 6px;\n            line-height: 1.3;\n        }\n.milestone-desc {\n            font-size: 12px;\n            color: rgba(255,255,255,0.75);\n            line-height: 1.5;\n        }\n.milestone-badge {\n            display: inline-block;\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 10px;\n            font-weight: 600;\n            padding: 3px 8px;\n            border-radius: 4px;\n            margin-top: 8px;\n            letter-spacing: 0.5px;\n        }\n.milestone-badge.gol